payload.text:
buatkan saya aplikasi laporan pelayanan ruang bedah, saya ingin aplikasi terdiri dari 6 menu besar 1. Menu Administratror (Menu Manajemen Data, Menu Pengaturan), 2. Menu Pelayanan (Menu Matriks Pelayanan Harian, Menu Laporan Operasi Harian, Menu Data Kondisi Bed), 3 Menu Administrasi (Menu Register Pasien, Menu Sensus Pasien, Menu Sensus Pelayanan, Menu Laporan Keuangan dan Visite Per SMF dan DPJP), 4. Menu PIC (Menu Indikator Mutu, Menu Absen Kehadiran DPJP, Menu Kepatuhan Visite, dan indikator Mutu lain, 5. Menu Jadwal dan Absen Manual, 6. Menu Insiden Report, untuk master data bisa ambil disini: 
import React, { useState } from 'react';
import { MasterData, User } from '../types';
import { Button } from './Button';
import { Trash2, Plus, Edit2, Save, X, User as UserIcon, Settings, Database, Activity, Map, Briefcase, Layout, BedDouble, AlertTriangle } from 'lucide-react';

interface DataManagementProps {
  masterData: MasterData;
  onSave: (newData: MasterData) => void;
}

type Tab = 'STAFF' | 'STRUCTURE' | 'MEDICS' | 'REFS';

export const DataManagement: React.FC<DataManagementProps> = ({ masterData, onSave }) => {
  const [activeTab, setActiveTab] = useState<Tab>('STAFF');

  // --- DELETE CONFIRMATION MODAL STATE ---
  const [deleteTarget, setDeleteTarget] = useState<{ 
      type: 'USER' | 'UNIT' | 'CLASS' | 'ROOM' | 'DOC' | 'KSM' | 'REF', 
      id: string, 
      name: string,
      subCategory?: keyof MasterData['refs'] 
  } | null>(null);

  // --- RENAME STATE (Used for Unit, Class, Room, KSM, Ref) ---
  const [renamingItem, setRenamingItem] = useState<{ 
      type: 'UNIT' | 'CLASS' | 'ROOM' | 'KSM' | 'REF', 
      oldName: string,
      subCategory?: keyof MasterData['refs']
  } | null>(null);
  const [renameInput, setRenameInput] = useState('');

  // --- ADD KSM MODAL STATE ---
  const [isKsmAddOpen, setIsKsmAddOpen] = useState(false);
  const [newKsmName, setNewKsmName] = useState('');

  // --- STAFF MANAGEMENT ---
  const [editingUser, setEditingUser] = useState<Partial<User> | null>(null);
  const [isUserFormOpen, setIsUserFormOpen] = useState(false);
  const [newPositionItem, setNewPositionItem] = useState(''); // Separate state for Position input

  const handleSaveUser = () => {
      if (!editingUser?.username || !editingUser?.name) return;

      const newUsers = [...masterData.users];
      const existingIndex = newUsers.findIndex(u => u.username === editingUser.username);

      const userPayload = {
          username: editingUser.username!,
          password: editingUser.password || '123456',
          name: editingUser.name!,
          role: editingUser.role || 'STAFF',
          position: editingUser.position || 'Staf',
      } as User;

      if (existingIndex >= 0) {
          if (!userPayload.password && newUsers[existingIndex].password) {
              userPayload.password = newUsers[existingIndex].password;
          }
          newUsers[existingIndex] = userPayload;
      } else {
          newUsers.push(userPayload);
      }

      const newNurses = newUsers
        .filter(u => u.role === 'PPJA' || u.position?.toLowerCase().includes('perawat'))
        .map(u => u.name);

      onSave({ ...masterData, users: newUsers, nurses: newNurses });
      setIsUserFormOpen(false);
      setEditingUser(null);
  };

  // --- GENERIC LIST MANAGEMENT ---
  // Using a dictionary to hold input values for different reference categories
  const [refInputs, setRefInputs] = useState<Record<string, string>>({});

  const handleRefInputChange = (key: string, value: string) => {
      setRefInputs(prev => ({ ...prev, [key]: value }));
  };

  const handleAddItem = (category: keyof MasterData | 'refs', subCategory?: keyof MasterData['refs'], specificValue?: string) => {
      let itemToAdd = specificValue;

      // If no specific value provided, try to find it in the refInputs state
      if (!itemToAdd && category === 'refs' && subCategory) {
          itemToAdd = refInputs[subCategory] || '';
      } else if (!itemToAdd && category === 'refs' && subCategory === 'positions') {
          itemToAdd = newPositionItem;
      }

      if (!itemToAdd) return;

      const newData = { ...masterData };

      if (category === 'refs' && subCategory) {
          newData.refs = { ...masterData.refs }; // Deep copy refs
          const list = newData.refs[subCategory] || [];
          if (!list.includes(itemToAdd)) {
             (newData.refs as any)[subCategory] = [...list, itemToAdd];
          }
          // Clear input
          if (subCategory === 'positions') setNewPositionItem('');
          else handleRefInputChange(subCategory, '');
      } 

      onSave(newData);
  };

  // Specific Handler for KSM Modal
  const saveNewKsm = () => {
      if (newKsmName) {
          handleAddItem('refs', 'ksmList', newKsmName);
          setIsKsmAddOpen(false);
          setNewKsmName('');
      }
  };

  // Unified Delete Handler
  const confirmDelete = () => {
      if (!deleteTarget) return;

      const newData = { ...masterData };

      switch (deleteTarget.type) {
          case 'USER':
              const newUsers = newData.users.filter(u => u.username !== deleteTarget.id);
              const newNurses = newUsers.filter(u => u.role === 'PPJA' || u.position?.toLowerCase().includes('perawat')).map(u => u.name);
              newData.users = newUsers;
              newData.nurses = newNurses;
              break;
          case 'UNIT':
              newData.units = newData.units.filter(u => u !== deleteTarget.id);
              delete newData.unitToClasses[deleteTarget.id];
              if (selectedUnit === deleteTarget.id) { setSelectedUnit(''); setSelectedClass(''); setSelectedRoom(''); }
              break;
          case 'CLASS':
              newData.unitToClasses = { ...newData.unitToClasses };
              newData.unitToClasses[selectedUnit] = newData.unitToClasses[selectedUnit].filter(c => c !== deleteTarget.id);
              const classKey = `${selectedUnit} - ${deleteTarget.id}`;
              delete newData.classToRooms[classKey];
              if (selectedClass === deleteTarget.id) { setSelectedClass(''); setSelectedRoom(''); }
              break;
          case 'ROOM':
              const key = `${selectedUnit} - ${selectedClass}`;
              if (newData.classToRooms[key]) {
                  newData.classToRooms[key] = newData.classToRooms[key].filter(r => r !== deleteTarget.id);
              }
              newData.rooms = newData.rooms.filter(r => r !== deleteTarget.id);
              delete newData.roomToBeds[deleteTarget.id];
              if (selectedRoom === deleteTarget.id) { setSelectedRoom(''); setBedsInput(''); }
              break;
          case 'DOC':
              newData.doctors = newData.doctors.filter(d => d !== deleteTarget.id);
              newData.doctorMetadata = { ...masterData.doctorMetadata };
              delete newData.doctorMetadata[deleteTarget.id];
              break;
          case 'KSM': // Handle KSM Deletion
          case 'REF': // Handle Generic Ref Deletion
              if (deleteTarget.subCategory) {
                  newData.refs = { ...masterData.refs };
                  newData.refs[deleteTarget.subCategory] = (newData.refs[deleteTarget.subCategory] || []).filter(i => i !== deleteTarget.id);
                  // If deleting KSM, maybe reset filter
                  if(deleteTarget.type === 'KSM' && ksmFilter === deleteTarget.id) setKsmFilter('All');
              } 
              break;
      }

      onSave(newData);
      setDeleteTarget(null);
  };

  // --- RENAME LOGIC ---
  const openRename = (type: 'UNIT' | 'CLASS' | 'ROOM' | 'KSM' | 'REF', oldName: string, subCategory?: keyof MasterData['refs']) => {
      setRenamingItem({ type, oldName, subCategory });
      setRenameInput(oldName);
  };

  const performRename = () => {
      if(!renamingItem || !renameInput || renameInput === renamingItem.oldName) {
          setRenamingItem(null); return;
      }
      const newData = { ...masterData };
      const { type, oldName, subCategory } = renamingItem;
      const newName = renameInput;

      if (type === 'UNIT') {
          newData.units = newData.units.map(u => u === oldName ? newName : u);
          const classes = newData.unitToClasses[oldName] || [];
          newData.unitToClasses[newName] = classes;
          delete newData.unitToClasses[oldName];
          classes.forEach(cls => {
              const oldKey = `${oldName} - ${cls}`;
              const newKey = `${newName} - ${cls}`;
              if (newData.classToRooms[oldKey]) {
                  newData.classToRooms[newKey] = newData.classToRooms[oldKey];
                  delete newData.classToRooms[oldKey];
              }
          });
          if (selectedUnit === oldName) setSelectedUnit(newName);
      } else if (type === 'CLASS') {
          const classes = newData.unitToClasses[selectedUnit] || [];
          newData.unitToClasses[selectedUnit] = classes.map(c => c === oldName ? newName : c);
          const oldKey = `${selectedUnit} - ${oldName}`;
          const newKey = `${selectedUnit} - ${newName}`;
          if (newData.classToRooms[oldKey]) {
              newData.classToRooms[newKey] = newData.classToRooms[oldKey];
              delete newData.classToRooms[oldKey];
          }
          if (selectedClass === oldName) setSelectedClass(newName);
      } else if (type === 'ROOM') {
          const key = `${selectedUnit} - ${selectedClass}`;
          const rooms = newData.classToRooms[key] || [];
          newData.classToRooms[key] = rooms.map(r => r === oldName ? newName : r);
          newData.rooms = newData.rooms.map(r => r === oldName ? newName : r);
          if (newData.roomToBeds[oldName]) {
              newData.roomToBeds[newName] = newData.roomToBeds[oldName];
              delete newData.roomToBeds[oldName];
          }
          if (selectedRoom === oldName) setSelectedRoom(newName);
      } else if ((type === 'KSM' || type === 'REF') && subCategory) {
          // Rename Item in Refs List
          newData.refs = { ...masterData.refs };
          const list = newData.refs[subCategory] || [];
          (newData.refs as any)[subCategory] = list.map(item => item === oldName ? newName : item);

          // If KSM, update metadata too
          if (type === 'KSM') {
              newData.doctorMetadata = { ...masterData.doctorMetadata };
              Object.keys(newData.doctorMetadata).forEach(docName => {
                  if (newData.doctorMetadata[docName].ksm === oldName) {
                      newData.doctorMetadata[docName] = { ...newData.doctorMetadata[docName], ksm: newName };
                  }
              });
              if (ksmFilter === oldName) setKsmFilter(newName);
          }
      }

      onSave(newData);
      setRenamingItem(null);
  };

  // --- STRUCTURE MANAGEMENT (HIERARCHY) ---
  const [selectedUnit, setSelectedUnit] = useState<string>('');
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [selectedRoom, setSelectedRoom] = useState<string>('');

  const [newUnitInput, setNewUnitInput] = useState('');
  const [newClassInput, setNewClassInput] = useState('');
  const [newRoomInput, setNewRoomInput] = useState('');
  const [bedsInput, setBedsInput] = useState('');

  // Structure Add Handlers
  const handleAddUnit = () => {
    if (!newUnitInput) return;
    const newData = { ...masterData };
    if (!newData.units.includes(newUnitInput)) {
        newData.units = [...newData.units, newUnitInput];
        newData.unitToClasses = { ...newData.unitToClasses, [newUnitInput]: [] };
        onSave(newData);
    }
    setNewUnitInput('');
  };
  const handleAddClass = () => {
    if (!newClassInput || !selectedUnit) return;
    const newData = { ...masterData };
    const classes = newData.unitToClasses[selectedUnit] || [];
    if (!classes.includes(newClassInput)) {
        newData.unitToClasses = { ...newData.unitToClasses, [selectedUnit]: [...classes, newClassInput] };
        const classKey = `${selectedUnit} - ${newClassInput}`;
        if (!newData.classToRooms[classKey]) {
            newData.classToRooms = { ...newData.classToRooms, [classKey]: [] };
        }
        onSave(newData);
    }
    setNewClassInput('');
  };
  const handleAddRoom = () => {
      if (!newRoomInput || !selectedClass || !selectedUnit) return;
      const newData = { ...masterData };
      const classKey = `${selectedUnit} - ${selectedClass}`;
      const rooms = newData.classToRooms[classKey] || [];
      if (!rooms.includes(newRoomInput)) {
          newData.classToRooms = { ...newData.classToRooms, [classKey]: [...rooms, newRoomInput] };
          if (!newData.rooms.includes(newRoomInput)) {
              newData.rooms = [...newData.rooms, newRoomInput];
          }
          if (!newData.roomToBeds[newRoomInput]) {
              newData.roomToBeds = { ...newData.roomToBeds, [newRoomInput]: [] };
          }
          onSave(newData);
      }
      setNewRoomInput('');
  };
  const handleSaveBeds = () => {
      if (!selectedRoom) return;
      const bedsArray = bedsInput.split(',').map(b => b.trim()).filter(b => b);
      const newData = { ...masterData };
      newData.roomToBeds = { ...newData.roomToBeds, [selectedRoom]: bedsArray };
      onSave(newData);
      alert('Data Bed tersimpan!');
  };

  // --- DOCTOR & KSM MANAGEMENT ---
  const [ksmFilter, setKsmFilter] = useState('All');
  const [editingDoc, setEditingDoc] = useState<{name: string, ksm: string, oldName?: string} | null>(null);
  const [isDocModalOpen, setIsDocModalOpen] = useState(false);

  const handleSaveDoc = () => {
      if (!editingDoc?.name) return;
      const newData = { ...masterData };

      // Ensure arrays are copied to trigger re-renders
      newData.doctors = [...masterData.doctors];
      newData.doctorMetadata = { ...masterData.doctorMetadata };

      if (editingDoc.oldName && editingDoc.oldName !== editingDoc.name) {
          // Rename Doctor
          newData.doctors = newData.doctors.map(d => d === editingDoc.oldName ? editingDoc.name : d);

          // Move Metadata
          if (newData.doctorMetadata[editingDoc.oldName]) {
              newData.doctorMetadata[editingDoc.name] = { 
                  ...newData.doctorMetadata[editingDoc.oldName], 
                  ksm: editingDoc.ksm 
              };
              delete newData.doctorMetadata[editingDoc.oldName];
          } else {
              newData.doctorMetadata[editingDoc.name] = { ksm: editingDoc.ksm };
          }
      } else {
          // New Doctor or Same Name Update
          if (!newData.doctors.includes(editingDoc.name)) {
              newData.doctors.push(editingDoc.name);
          }
          newData.doctorMetadata[editingDoc.name] = { ksm: editingDoc.ksm };
      }

      onSave(newData);
      setIsDocModalOpen(false);
      setEditingDoc(null);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border min-h-[600px] flex flex-col relative">

      {/* DELETE CONFIRMATION MODAL */}
      {deleteTarget && (
          <div className="fixed inset-0 bg-black/50 z-[1100] flex items-center justify-center p-4">
              <div className="bg-white rounded-lg p-6 shadow-xl w-full max-w-sm animate-fade-in">
                  <div className="flex items-center gap-3 mb-4 text-red-600">
                      <div className="bg-red-100 p-2 rounded-full">
                          <AlertTriangle size={24}/>
                      </div>
                      <h3 className="font-bold text-lg text-gray-800">Konfirmasi Hapus</h3>
                  </div>
                  <p className="text-gray-600 mb-6">
                      Anda yakin ingin menghapus <strong>{deleteTarget.name}</strong>? 
                      {deleteTarget.type === 'UNIT' && " Data kelas dan ruangan didalamnya akan menjadi yatim."}
                      {deleteTarget.type === 'ROOM' && " Data Bed juga akan terhapus."}
                      {deleteTarget.type === 'KSM' && " Label KSM pada dokter terkait akan hilang."}
                  </p>
                  <div className="flex justify-end gap-2">
                      <Button variant="secondary" onClick={() => setDeleteTarget(null)}>Batal</Button>
                      <Button variant="danger" onClick={confirmDelete}>Hapus Data</Button>
                  </div>
              </div>
          </div>
      )}

      {/* RENAME MODAL POPUP */}
      {renamingItem && (
          <div className="fixed inset-0 bg-black/50 z-[1050] flex items-center justify-center p-4">
              <div className="bg-white rounded-lg p-6 shadow-xl w-full max-w-sm animate-fade-in">
                  <h3 className="font-bold text-gray-800 mb-4">
                      Edit {renamingItem.type === 'UNIT' ? 'Unit' : renamingItem.type === 'CLASS' ? 'Kelas' : renamingItem.type === 'ROOM' ? 'Ruangan' : renamingItem.type === 'KSM' ? 'KSM' : 'Referensi'}
                  </h3>
                  <input 
                    className="w-full border rounded p-2 mb-4" 
                    value={renameInput} 
                    onChange={e => setRenameInput(e.target.value)}
                    autoFocus
                  />
                  <div className="flex justify-end gap-2">
                      <Button variant="secondary" size="sm" onClick={() => setRenamingItem(null)}>Batal</Button>
                      <Button size="sm" onClick={performRename}>Simpan</Button>
                  </div>
              </div>
          </div>
      )}

      {/* ADD KSM MODAL (High Z-Index to appear above Doctor Modal) */}
      {isKsmAddOpen && (
          <div className="fixed inset-0 bg-black/50 z-[1200] flex items-center justify-center p-4">
              <div className="bg-white rounded-lg p-6 shadow-xl w-full max-w-sm animate-fade-in">
                  <h3 className="font-bold text-gray-800 mb-4">Tambah KSM Baru</h3>
                  <input 
                    className="w-full border rounded p-2 mb-4" 
                    value={newKsmName} 
                    onChange={e => setNewKsmName(e.target.value)}
                    placeholder="Nama KSM (Contoh: Bedah Onkologi)"
                    autoFocus
                    onKeyDown={(e) => { if (e.key === 'Enter') saveNewKsm(); }}
                  />
                  <div className="flex justify-end gap-2">
                      <Button variant="secondary" size="sm" onClick={() => setIsKsmAddOpen(false)}>Batal</Button>
                      <Button size="sm" onClick={saveNewKsm}>Simpan KSM</Button>
                  </div>
              </div>
          </div>
      )}

      {/* DOCTOR MODAL */}
      {isDocModalOpen && (
          <div className="fixed inset-0 bg-black/50 z-[1050] flex items-center justify-center p-4">
              <div className="bg-white rounded-lg p-6 shadow-xl w-full max-w-md animate-fade-in">
                  <h3 className="font-bold text-gray-800 mb-4">{editingDoc?.oldName ? 'Edit Dokter' : 'Tambah Dokter Baru'}</h3>
                  <div className="space-y-4">
                      <div>
                          <label className="block text-xs font-bold text-gray-500 mb-1">Nama Dokter (Lengkap dengan Gelar)</label>
                          <input 
                              className="w-full border rounded p-2 text-sm" 
                              value={editingDoc?.name || ''} 
                              onChange={e => setEditingDoc(prev => prev ? ({...prev, name: e.target.value}) : null)}
                              placeholder="dr. Nama Lengkap, Sp.X"
                          />
                      </div>
                      <div>
                          <label className="block text-xs font-bold text-gray-500 mb-1">Kelompok Staf Medis (KSM)</label>
                          <div className="flex gap-2">
                              <select 
                                  className="w-full border rounded p-2 text-sm flex-1"
                                  value={editingDoc?.ksm || ''}
                                  onChange={e => setEditingDoc(prev => prev ? ({...prev, ksm: e.target.value}) : null)}
                              >
                                  <option value="">-- Pilih KSM --</option>
                                  {(masterData.refs.ksmList || []).sort().map(k => <option key={k} value={k}>{k}</option>)}
                              </select>
                              <button 
                                  onClick={() => setIsKsmAddOpen(true)}
                                  className="bg-primary-50 text-primary-600 border border-primary-200 rounded px-3 hover:bg-primary-100"
                                  title="Tambah KSM Baru"
                                  type="button"
                              >
                                  <Plus size={16}/>
                              </button>
                          </div>
                      </div>
                  </div>
                  <div className="flex justify-end gap-2 mt-6">
                      <Button variant="secondary" size="sm" onClick={() => { setIsDocModalOpen(false); setEditingDoc(null); }}>Batal</Button>
                      <Button size="sm" onClick={handleSaveDoc}>Simpan Dokter</Button>
                  </div>
              </div>
          </div>
      )}

      <div className="flex border-b">
        <button onClick={() => setActiveTab('STAFF')} className={`flex-1 py-4 text-sm font-bold flex justify-center items-center gap-2 ${activeTab === 'STAFF' ? 'text-primary-600 border-b-2 border-primary-600 bg-primary-50' : 'text-gray-500 hover:bg-gray-50'}`}>
            <UserIcon size={18}/> Manajemen Staf (User)
        </button>
        <button onClick={() => setActiveTab('STRUCTURE')} className={`flex-1 py-4 text-sm font-bold flex justify-center items-center gap-2 ${activeTab === 'STRUCTURE' ? 'text-primary-600 border-b-2 border-primary-600 bg-primary-50' : 'text-gray-500 hover:bg-gray-50'}`}>
            <Map size={18}/> Struktur & Bed
        </button>
        <button onClick={() => setActiveTab('MEDICS')} className={`flex-1 py-4 text-sm font-bold flex justify-center items-center gap-2 ${activeTab === 'MEDICS' ? 'text-primary-600 border-b-2 border-primary-600 bg-primary-50' : 'text-gray-500 hover:bg-gray-50'}`}>
            <Activity size={18}/> Medis (DPJP)
        </button>
        <button onClick={() => setActiveTab('REFS')} className={`flex-1 py-4 text-sm font-bold flex justify-center items-center gap-2 ${activeTab === 'REFS' ? 'text-primary-600 border-b-2 border-primary-600 bg-primary-50' : 'text-gray-500 hover:bg-gray-50'}`}>
            <Database size={18}/> Data Referensi
        </button>
      </div>

      <div className="p-6 flex-1 overflow-y-auto bg-gray-50">

        {/* --- STAFF TAB --- */}
        {activeTab === 'STAFF' && (
            <div className="space-y-6">

                {/* 1. Posisi/Jabatan Manager */}
                <div className="bg-blue-50 p-4 rounded-lg border border-blue-100 mb-6">
                    <h4 className="font-bold text-blue-800 text-sm mb-2 flex items-center"><Briefcase size={16} className="mr-2"/> Kelola Daftar Jabatan / Posisi</h4>
                    <div className="flex gap-2 mb-2">
                         <input 
                            className="flex-1 border rounded px-3 py-1.5 text-sm" 
                            placeholder="Tambah Jabatan Baru..." 
                            value={newPositionItem}
                            onChange={(e) => setNewPositionItem(e.target.value)}
                         />
                         <Button size="sm" onClick={() => handleAddItem('refs', 'positions')}>Tambah Jabatan</Button>
                    </div>
                    <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto">
                        {masterData.refs.positions.map(pos => (
                            <span key={pos} className="bg-white text-gray-700 px-2 py-1 rounded border text-xs flex items-center gap-1 group">
                                {pos}
                                <button 
                                    onClick={() => setDeleteTarget({ type: 'REF', id: pos, name: pos, subCategory: 'positions' })} 
                                    className="text-gray-300 hover:text-red-500 ml-1"
                                    type="button"
                                >
                                    <X size={12}/>
                                </button>
                            </span>
                        ))}
                    </div>
                </div>

                {/* 2. User Manager */}
                <div className="flex justify-between items-center">
                    <h3 className="text-lg font-bold text-gray-800">Daftar Akun Pengguna</h3>
                    <Button onClick={() => { setEditingUser({}); setIsUserFormOpen(true); }} size="sm">
                        <Plus size={16} className="mr-1"/> Tambah User
                    </Button>
                </div>

                {isUserFormOpen && (
                    <div className="fixed inset-0 bg-black/50 z-[1050] flex items-center justify-center p-4">
                        <div className="bg-white p-6 border rounded-lg shadow-xl mb-4 animate-fade-in w-full max-w-lg">
                        <h4 className="font-bold text-gray-700 mb-4">{editingUser?.username ? 'Edit User' : 'User Baru'}</h4>
                        <div className="grid grid-cols-2 gap-4 mb-4">
                            <div>
                                <label className="block text-xs font-bold text-gray-500">Username</label>
                                <input className="w-full border p-2 rounded" value={editingUser?.username || ''} onChange={e => setEditingUser({...editingUser, username: e.target.value})} disabled={!!masterData.users.find(u => u.username === editingUser?.username && editingUser !== u)}/>
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-gray-500">Password</label>
                                <input className="w-full border p-2 rounded" type="text" placeholder="Kosongkan jika tidak ubah" value={editingUser?.password || ''} onChange={e => setEditingUser({...editingUser, password: e.target.value})}/>
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-gray-500">Nama Lengkap</label>
                                <input className="w-full border p-2 rounded" value={editingUser?.name || ''} onChange={e => setEditingUser({...editingUser, name: e.target.value})}/>
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-gray-500">Jabatan / Posisi</label>
                                <select 
                                    className="w-full border p-2 rounded" 
                                    value={editingUser?.position || ''} 
