interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost' | 'success' | 'warning';
  size?: 'sm' | 'md' | 'lg';
  children: React.ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ 
  variant = 'primary', 
  size = 'md', 
  children, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center font-medium rounded-lg transition-all focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-blue-600 text-white hover:bg-blue-700 shadow-sm",
    secondary: "bg-gray-100 text-gray-700 hover:bg-gray-200",
    danger: "bg-red-500 text-white hover:bg-red-600",
    success: "bg-emerald-500 text-white hover:bg-emerald-600",
    warning: "bg-amber-500 text-white hover:bg-amber-600",
    ghost: "bg-transparent text-gray-600 hover:bg-gray-100",
  };

  const sizes = {
    sm: "px-3 py-1.5 text-xs",
    md: "px-4 py-2 text-sm",
    lg: "px-6 py-3 text-base",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React, { useState } from 'react';
import { MasterData, User } from '../../types';
import { Button } from '../Button';
import { Trash2, Plus, Edit2, Save, X, User as UserIcon, Map, Activity, Database, Briefcase, Layout, BedDouble, AlertTriangle } from 'lucide-react';

interface DataManagementProps {
  masterData: MasterData;
  onSave: (newData: MasterData) => void;
}

type Tab = 'STAFF' | 'STRUCTURE' | 'MEDICS' | 'REFS';

export const DataManagement: React.FC<DataManagementProps> = ({ masterData, onSave }) => {
  const [activeTab, setActiveTab] = useState<Tab>('STAFF');

  const [deleteTarget, setDeleteTarget] = useState<{ 
      type: 'USER' | 'UNIT' | 'CLASS' | 'ROOM' | 'DOC' | 'KSM' | 'REF', 
      id: string, 
      name: string,
      subCategory?: keyof MasterData['refs'] 
  } | null>(null);

  const [renamingItem, setRenamingItem] = useState<{ 
      type: 'UNIT' | 'CLASS' | 'ROOM' | 'KSM' | 'REF', 
      oldName: string,
      subCategory?: keyof MasterData['refs']
  } | null>(null);
  const [renameInput, setRenameInput] = useState('');

  const [isKsmAddOpen, setIsKsmAddOpen] = useState(false);
  const [newKsmName, setNewKsmName] = useState('');

  const [editingUser, setEditingUser] = useState<Partial<User> | null>(null);
  const [isUserFormOpen, setIsUserFormOpen] = useState(false);
  const [newPositionItem, setNewPositionItem] = useState('');

  const handleSaveUser = () => {
      if (!editingUser?.username || !editingUser?.name) return;

      const newUsers = [...masterData.users];
      const existingIndex = newUsers.findIndex(u => u.username === editingUser.username);

      const userPayload = {
          username: editingUser.username!,
          password: editingUser.password || '123456',
          name: editingUser.name!,
          role: editingUser.role || 'STAFF',
          position: editingUser.position || 'Staf',
      } as User;

      if (existingIndex >= 0) {
          if (!userPayload.password && newUsers[existingIndex].password) {
              userPayload.password = newUsers[existingIndex].password;
          }
          newUsers[existingIndex] = userPayload;
      } else {
          newUsers.push(userPayload);
      }

      const newNurses = newUsers
        .filter(u => u.role === 'PPJA' || u.position?.toLowerCase().includes('perawat'))
        .map(u => u.name);

      onSave({ ...masterData, users: newUsers, nurses: newNurses });
      setIsUserFormOpen(false);
      setEditingUser(null);
  };

  const [refInputs, setRefInputs] = useState<Record<string, string>>({});

  const handleRefInputChange = (key: string, value: string) => {
      setRefInputs(prev => ({ ...prev, [key]: value }));
  };

  const handleAddItem = (category: keyof MasterData | 'refs', subCategory?: keyof MasterData['refs'], specificValue?: string) => {
      let itemToAdd = specificValue;

      if (!itemToAdd && category === 'refs' && subCategory) {
          itemToAdd = refInputs[subCategory] || '';
      } else if (!itemToAdd && category === 'refs' && subCategory === 'positions') {
          itemToAdd = newPositionItem;
      }

      if (!itemToAdd) return;

      const newData = { ...masterData };

      if (category === 'refs' && subCategory) {
          newData.refs = { ...masterData.refs };
          const list = (newData.refs as any)[subCategory] || [];
          if (!list.includes(itemToAdd)) {
             (newData.refs as any)[subCategory] = [...list, itemToAdd];
          }
          if (subCategory === 'positions') setNewPositionItem('');
          else handleRefInputChange(subCategory, '');
      } 

      onSave(newData);
  };

  const saveNewKsm = () => {
      if (newKsmName) {
          handleAddItem('refs', 'ksmList', newKsmName);
          setIsKsmAddOpen(false);
          setNewKsmName('');
      }
  };

  const [selectedUnit, setSelectedUnit] = useState<string>('');
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [selectedRoom, setSelectedRoom] = useState<string>('');

  const [newUnitInput, setNewUnitInput] = useState('');
  const [newClassInput, setNewClassInput] = useState('');
  const [newRoomInput, setNewRoomInput] = useState('');
  const [bedsInput, setBedsInput] = useState('');

  const confirmDelete = () => {
      if (!deleteTarget) return;
      const newData = { ...masterData };
      switch (deleteTarget.type) {
          case 'USER':
              newData.users = newData.users.filter(u => u.username !== deleteTarget.id);
              newData.nurses = newData.users.filter(u => u.role === 'PPJA' || u.position?.toLowerCase().includes('perawat')).map(u => u.name);
              break;
          case 'UNIT':
              newData.units = newData.units.filter(u => u !== deleteTarget.id);
              delete newData.unitToClasses[deleteTarget.id];
              break;
          case 'CLASS':
              newData.unitToClasses[selectedUnit] = (newData.unitToClasses[selectedUnit] || []).filter(c => c !== deleteTarget.id);
              break;
          case 'ROOM':
              const key = `${selectedUnit} - ${selectedClass}`;
              newData.classToRooms[key] = (newData.classToRooms[key] || []).filter(r => r !== deleteTarget.id);
              newData.rooms = newData.rooms.filter(r => r !== deleteTarget.id);
              delete newData.roomToBeds[deleteTarget.id];
              break;
          case 'DOC':
              newData.doctors = newData.doctors.filter(d => d !== deleteTarget.id);
              delete newData.doctorMetadata[deleteTarget.id];
              break;
          case 'KSM':
          case 'REF':
              if (deleteTarget.subCategory) {
                  (newData.refs as any)[deleteTarget.subCategory] = ((newData.refs as any)[deleteTarget.subCategory] || []).filter((i: string) => i !== deleteTarget.id);
              } 
              break;
      }
      onSave(newData);
      setDeleteTarget(null);
  };

  const performRename = () => {
    if(!renamingItem || !renameInput || renameInput === renamingItem.oldName) {
        setRenamingItem(null); return;
    }
    const newData = { ...masterData };
    const { type, oldName, subCategory } = renamingItem;
    const newName = renameInput;

    if (type === 'UNIT') {
        newData.units = newData.units.map(u => u === oldName ? newName : u);
        newData.unitToClasses[newName] = newData.unitToClasses[oldName] || [];
        delete newData.unitToClasses[oldName];
    } else if (type === 'CLASS') {
        newData.unitToClasses[selectedUnit] = (newData.unitToClasses[selectedUnit] || []).map(c => c === oldName ? newName : c);
    } else if (type === 'ROOM') {
        const key = `${selectedUnit} - ${selectedClass}`;
        newData.classToRooms[key] = (newData.classToRooms[key] || []).map(r => r === oldName ? newName : r);
        newData.rooms = newData.rooms.map(r => r === oldName ? newName : r);
    } else if (subCategory) {
        (newData.refs as any)[subCategory] = ((newData.refs as any)[subCategory] || []).map((i: string) => i === oldName ? newName : i);
    }

    onSave(newData);
    setRenamingItem(null);
  };

  const [ksmFilter, setKsmFilter] = useState('All');
  const [editingDoc, setEditingDoc] = useState<{name: string, ksm: string, oldName?: string} | null>(null);
  const [isDocModalOpen, setIsDocModalOpen] = useState(false);

  const handleSaveDoc = () => {
      if (!editingDoc?.name) return;
      const newData = { ...masterData };
      if (editingDoc.oldName) {
          newData.doctors = newData.doctors.map(d => d === editingDoc.oldName ? editingDoc.name : d);
          delete newData.doctorMetadata[editingDoc.oldName];
      } else if (!newData.doctors.includes(editingDoc.name)) {
          newData.doctors.push(editingDoc.name);
      }
      newData.doctorMetadata[editingDoc.name] = { ksm: editingDoc.ksm };
      onSave(newData);
      setIsDocModalOpen(false);
      setEditingDoc(null);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border min-h-[600px] flex flex-col relative overflow-hidden">
      {/* MODALS RENDERED HERE FOR DEPTH */}
      {deleteTarget && (
        <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-lg p-6 w-full max-w-sm">
            <h3 className="font-bold text-lg mb-2 text-red-600 flex items-center gap-2"><AlertTriangle/> Konfirmasi</h3>
            <p className="text-sm text-gray-600 mb-6">Hapus data <b>{deleteTarget.name}</b>?</p>
            <div className="flex justify-end gap-2">
              <Button variant="secondary" onClick={() => setDeleteTarget(null)}>Batal</Button>
              <Button variant="danger" onClick={confirmDelete}>Hapus</Button>
            </div>
          </div>
        </div>
      )}

      {renamingItem && (
        <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-lg p-6 w-full max-w-sm">
            <h3 className="font-bold mb-4">Edit Nama</h3>
            <input className="w-full border p-2 mb-4" value={renameInput} onChange={e => setRenameInput(e.target.value)} autoFocus />
            <div className="flex justify-end gap-2">
              <Button variant="secondary" onClick={() => setRenamingItem(null)}>Batal</Button>
              <Button onClick={performRename}>Simpan</Button>
            </div>
          </div>
        </div>
      )}

      {isDocModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-lg p-6 w-full max-w-md">
            <h3 className="font-bold mb-4">{editingDoc?.oldName ? 'Edit Dokter' : 'Tambah Dokter'}</h3>
            <input className="w-full border p-2 mb-4 text-sm" placeholder="Nama Dokter" value={editingDoc?.name} onChange={e => setEditingDoc({...editingDoc!, name: e.target.value})} />
            <select className="w-full border p-2 mb-4 text-sm" value={editingDoc?.ksm} onChange={e => setEditingDoc({...editingDoc!, ksm: e.target.value})}>
              <option value="">Pilih KSM</option>
              {masterData.refs.ksmList.map(k => <option key={k} value={k}>{k}</option>)}
            </select>
            <div className="flex justify-end gap-2">
              <Button variant="secondary" onClick={() => setIsDocModalOpen(false)}>Batal</Button>
              <Button onClick={handleSaveDoc}>Simpan</Button>
            </div>
          </div>
        </div>
      )}

      <div className="flex border-b">
        {[
          { id: 'STAFF', icon: <UserIcon size={18}/>, label: 'Staf' },
          { id: 'STRUCTURE', icon: <Map size={18}/>, label: 'Struktur' },
          { id: 'MEDICS', icon: <Activity size={18}/>, label: 'DPJP' },
          { id: 'REFS', icon: <Database size={18}/>, label: 'Referensi' }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveTab(tab.id as Tab)} 
            className={`flex-1 py-4 text-sm font-bold flex justify-center items-center gap-2 ${activeTab === tab.id ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50' : 'text-gray-500 hover:bg-gray-50'}`}
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      <div className="p-6 flex-1 overflow-y-auto bg-gray-50">
        {activeTab === 'STAFF' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold">Daftar Akun Pengguna</h3>
              <Button onClick={() => { setEditingUser({}); setIsUserFormOpen(true); }} size="sm"><Plus size={16}/> Tambah User</Button>
            </div>
            {isUserFormOpen && (
               <div className="p-4 bg-white border rounded shadow-sm grid grid-cols-2 gap-4">
                  <input className="border p-2" placeholder="Username" value={editingUser?.username} onChange={e => setEditingUser({...editingUser!, username: e.target.value})} />
                  <input className="border p-2" placeholder="Nama" value={editingUser?.name} onChange={e => setEditingUser({...editingUser!, name: e.target.value})} />
                  <select className="border p-2" value={editingUser?.role} onChange={e => setEditingUser({...editingUser!, role: e.target.value as any})}>
                    <option value="STAFF">STAFF</option>
                    <option value="PPJA">PPJA</option>
                    <option value="PIC">PIC</option>
                    <option value="ADMIN_RUANGAN">ADMIN</option>
                    <option value="SUPER_ADMIN">SUPER ADMIN</option>
                  </select>
                  <div className="flex gap-2">
                    <Button variant="secondary" onClick={() => setIsUserFormOpen(false)}>Batal</Button>
                    <Button onClick={handleSaveUser}>Simpan</Button>
                  </div>
               </div>
            )}
            <table className="w-full bg-white rounded border overflow-hidden text-sm">
              <thead className="bg-gray-100">
                <tr><th className="p-3 text-left">Nama</th><th className="p-3 text-left">Username</th><th className="p-3 text-left">Role</th><th className="p-3 text-right">Aksi</th></tr>
              </thead>
              <tbody>
                {masterData.users.map(u => (
                  <tr key={u.username} className="border-t">
                    <td className="p-3">{u.name}</td><td className="p-3">{u.username}</td><td className="p-3">{u.role}</td>
                    <td className="p-3 text-right"><button onClick={() => { setEditingUser(u); setIsUserFormOpen(true); }}><Edit2 size={16}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {activeTab === 'STRUCTURE' && (
           <div className="grid grid-cols-3 gap-4">
              <div className="border bg-white rounded p-4 h-96 flex flex-col">
                 <h4 className="font-bold mb-2">1. Unit</h4>
                 <div className="flex gap-2 mb-2"><input className="border text-xs flex-1" value={newUnitInput} onChange={e => setNewUnitInput(e.target.value)}/><Button size="sm" onClick={() => { if(newUnitInput) { onSave({...masterData, units: [...masterData.units, newUnitInput]}); setNewUnitInput(''); } }}><Plus size={12}/></Button></div>
                 <div className="overflow-y-auto space-y-1">
                    {masterData.units.map(u => <div key={u} onClick={() => setSelectedUnit(u)} className={`p-2 text-xs rounded cursor-pointer ${selectedUnit === u ? 'bg-blue-100' : 'hover:bg-gray-100'}`}>{u}</div>)}
                 </div>
              </div>
              <div className="border bg-white rounded p-4 h-96 flex flex-col">
                 <h4 className="font-bold mb-2">2. Kelas ({selectedUnit || 'Pilih Unit'})</h4>
                 <div className="overflow-y-auto space-y-1">
                    {(masterData.unitToClasses[selectedUnit] || []).map(c => <div key={c} onClick={() => setSelectedClass(c)} className={`p-2 text-xs rounded cursor-pointer ${selectedClass === c ? 'bg-blue-100' : 'hover:bg-gray-100'}`}>{c}</div>)}
                 </div>
              </div>
              <div className="border bg-white rounded p-4 h-96 flex flex-col">
                 <h4 className="font-bold mb-2">3. Ruangan</h4>
                 <div className="overflow-y-auto space-y-1">
                    {(masterData.classToRooms[`${selectedUnit} - ${selectedClass}`] || []).map(r => <div key={r} className="p-2 text-xs hover:bg-gray-100">{r}</div>)}
                 </div>
              </div>
           </div>
        )}

        {activeTab === 'REFS' && (
          <div className="grid grid-cols-2 gap-6">
             {Object.entries(masterData.refs).filter(([k]) => ['asalMasuk', 'caraBayar', 'incidentTypes'].includes(k)).map(([key, list]) => (
                <div key={key} className="bg-white p-4 border rounded">
                   <h4 className="font-bold capitalize mb-4 text-blue-800">{key.replace(/([A-Z])/g, ' $1')}</h4>
                   <div className="flex gap-2 mb-4">
                      <input className="border flex-1 p-2 text-sm" placeholder="Tambah..." value={refInputs[key] || ''} onChange={e => handleRefInputChange(key, e.target.value)} />
                      <Button onClick={() => handleAddItem('refs', key as any)}><Plus size={16}/></Button>
                   </div>
                   <div className="max-h-40 overflow-y-auto divide-y">
                      {(list as string[]).map(item => (
                         <div key={item} className="py-2 flex justify-between group">
                            <span className="text-sm">{item}</span>
                            <button className="text-red-300 opacity-0 group-hover:opacity-100" onClick={() => setDeleteTarget({ type: 'REF', id: item, name: item, subCategory: key as any })}><X size={14}/></button>
                         </div>
                      ))}
                   </div>
                </div>
             ))}
          </div>
        )}
      </div>
    </div>
  );
};

