import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { DataManagement } from './components/Administrator/DataManagement';
import { Button } from './components/Button';
import { INITIAL_MASTER_DATA } from './constants';
import { MasterData, User, Patient, SurgeryLog } from './types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  LineChart, Line
} from 'recharts';
import { Plus, Users, Search, Filter, Calendar } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>({ 
    username: 'admin', 
    name: 'Admin Ruang Bedah', 
    role: 'SUPER_ADMIN', 
    position: 'Kepala Instalasi' 
  });
  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [masterData, setMasterData] = useState<MasterData>(INITIAL_MASTER_DATA);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [surgeryLogs, setSurgeryLogs] = useState<SurgeryLog[]>([]);

  // PERSISTENCE
  useEffect(() => {
    const savedData = localStorage.getItem('or_master_data');
    if (savedData) setMasterData(JSON.parse(savedData));
  }, []);

  const saveMasterData = (newData: MasterData) => {
    setMasterData(newData);
