import { Plus, TrendingUp, TrendingDown, Wallet, Calendar, Search } from 'lucide-react';

interface FinanceModuleProps {
  records: FinanceRecord[];
  onAddRecord: (record: FinanceRecord) => void;
}

export const FinanceModule: React.FC<FinanceModuleProps> = ({ records, onAddRecord }) => {
  const [showForm, setShowForm] = useState(false);
  const [filter, setFilter] = useState<'ALL' | 'INCOME' | 'EXPENSE'>('ALL');
  const [newRecord, setNewRecord] = useState<Partial<FinanceRecord>>({
    type: 'INCOME',
    date: new Date().toISOString().split('T')[0],
    amount: 0,
    category: '',
    description: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRecord.amount || !newRecord.category) return;

    onAddRecord({
      ...newRecord,
      id: Date.now().toString(),
      recordedBy: 'Admin'
    } as FinanceRecord);

    setShowForm(false);
    setNewRecord({ type: 'INCOME', date: new Date().toISOString().split('T')[0], amount: 0, category: '', description: '' });
  };

  const totals = records.reduce((acc, curr) => {
    if (curr.type === 'INCOME') acc.income += curr.amount;
    else acc.expense += curr.amount;
    return acc;
  }, { income: 0, expense: 0 });

  const filteredRecords = records.filter(r => filter === 'ALL' || r.type === filter);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-5 rounded-xl border shadow-sm border-l-4 border-l-emerald-500">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-xs font-bold text-gray-400 uppercase">Total Pendapatan</p>
              <h3 className="text-2xl font-bold text-emerald-600 mt-1">Rp {totals.income.toLocaleString('id-ID')}</h3>
            </div>
            <div className="p-2 bg-emerald-50 rounded-lg text-emerald-600"><TrendingUp size={20}/></div>
          </div>
        </div>
        <div className="bg-white p-5 rounded-xl border shadow-sm border-l-4 border-l-red-500">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-xs font-bold text-gray-400 uppercase">Total Biaya Operasional</p>
              <h3 className="text-2xl font-bold text-red-600 mt-1">Rp {totals.expense.toLocaleString('id-ID')}</h3>
            </div>
            <div className="p-2 bg-red-50 rounded-lg text-red-600"><TrendingDown size={20}/></div>
          </div>
        </div>
        <div className="bg-white p-5 rounded-xl border shadow-sm border-l-4 border-l-blue-500">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-xs font-bold text-gray-400 uppercase">Saldo Netto</p>
              <h3 className="text-2xl font-bold text-blue-600 mt-1">Rp {(totals.income - totals.expense).toLocaleString('id-ID')}</h3>
            </div>
            <div className="p-2 bg-blue-50 rounded-lg text-blue-600"><Wallet size={20}/></div>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
        <div className="p-4 border-b bg-gray-50 flex flex-wrap justify-between items-center gap-4">
