import React, { useState } from 'react';
import { IncidentReport } from '../../types';
import { Button } from '../Button';
import { AlertCircle, Plus, CheckCircle2, Clock, ShieldAlert, Send } from 'lucide-react';

interface IncidentModuleProps {
  reports: IncidentReport[];
  onAddReport: (report: IncidentReport) => void;
  onUpdateStatus: (id: string, status: IncidentReport['status'], notes?: string) => void;
}

export const IncidentModule: React.FC<IncidentModuleProps> = ({ reports, onAddReport, onUpdateStatus }) => {
  const [showForm, setShowForm] = useState(false);
  const [activeNotification, setActiveNotification] = useState<string | null>(null);
  const [newReport, setNewReport] = useState<Partial<IncidentReport>>({
    severity: 'YELLOW',
    incidentType: '',
    location: '',
    chronology: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const report: IncidentReport = {
      ...newReport,
      id: Date.now().toString(),
      date: new Date().toISOString().split('T')[0],
      time: new Date().toTimeString().split(' ')[0],
      reporterName: 'User',
      status: 'NEW',
    } as IncidentReport;

    onAddReport(report);
    setShowForm(false);
    setActiveNotification(`Insiden baru "${report.incidentType}" telah dikirim ke PIC!`);
    setTimeout(() => setActiveNotification(null), 5000);
  };

  const severityColors = {
    GREEN: 'bg-emerald-100 text-emerald-700 border-emerald-200',
    YELLOW: 'bg-amber-100 text-amber-700 border-amber-200',
    RED: 'bg-red-100 text-red-700 border-red-200'
  };

  const statusIcons = {
    NEW: <Clock size={14} className="text-red-500" />,
    INVESTIGATING: <AlertCircle size={14} className="text-amber-500" />,
    RESOLVED: <CheckCircle2 size={14} className="text-emerald-500" />
  };

  return (
    <div className="space-y-4">
      {activeNotification && (
        <div className="bg-slate-900 text-white p-4 rounded-xl shadow-2xl flex items-center justify-between animate-fade-in border-l-4 border-l-blue-400">
          <div className="flex items-center gap-3">
            <ShieldAlert className="text-blue-400" />
            <p className="text-sm font-medium">{activeNotification}</p>
          </div>
          <Button variant="ghost" size="sm" onClick={() => setActiveNotification(null)}>Tutup</Button>
        </div>
      )}

      <div className="flex justify-between items-center bg-white p-4 rounded-xl border shadow-sm">
        <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800">
          <AlertCircle className="text-red-500"/> Daftar Laporan Insiden
        </h3>
        <Button onClick={() => setShowForm(!showForm)} size="sm">
          <Plus size={16} className="mr-2"/> Laporkan Insiden
        </Button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-xl border-2 border-red-100 shadow-lg animate-fade-in">
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="col-span-2">
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Tipe Insiden</label>
              <input required className="w-full border rounded-lg p-3 text-sm" placeholder="Judul singkat insiden..." value={newReport.incidentType} onChange={e => setNewReport({...newReport, incidentType: e.target.value})}/>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Lokasi</label>
              <input required className="w-full border rounded-lg p-3 text-sm" placeholder="Misal: OK 1" value={newReport.location} onChange={e => setNewReport({...newReport, location: e.target.value})}/>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Tingkat Bahaya (Severity)</label>
              <select className="w-full border rounded-lg p-3 text-sm" value={newReport.severity} onChange={e => setNewReport({...newReport, severity: e.target.value as any})}>
                <option value="GREEN">Hijau (Rendah)</option>
                <option value="YELLOW">Kuning (Sedang)</option>
                <option value="RED">Merah (Tinggi)</option>
              </select>
            </div>
            <div className="col-span-2">
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Kronologi</label>
              <textarea required className="w-full border rounded-lg p-3 text-sm min-h-[100px]" placeholder="Deskripsikan kejadian secara detail..." value={newReport.chronology} onChange={e => setNewReport({...newReport, chronology: e.target.value})}/>
            </div>
            <div className="col-span-2 flex justify-end gap-2">
              <Button type="button" variant="secondary" onClick={() => setShowForm(false)}>Batal</Button>
              <Button type="submit" variant="danger"><Send size={16} className="mr-2"/> Kirim Laporan</Button>
            </div>
          </form>
        </div>
      )}

      <div className="grid grid-cols-1 gap-4">
        {reports.length > 0 ? reports.sort((a,b) => b.date.localeCompare(a.date)).map(report => (
          <div key={report.id} className="bg-white border rounded-xl p-5 shadow-sm hover:shadow-md transition-shadow">
            <div className="flex justify-between items-start mb-4">
              <div className="flex items-center gap-3">
                <span className={`px-2 py-1 rounded text-[10px] font-bold border ${severityColors[report.severity]}`}>
                  SEVERITY: {report.severity}
                </span>
                <span className="text-xs text-gray-400 font-medium">{report.date} | {report.time}</span>
              </div>
              <div className="flex items-center gap-2">
                {statusIcons[report.status]}
                <span className="text-[10px] font-bold uppercase">{report.status.replace('_', ' ')}</span>
              </div>
            </div>

            <h4 className="font-bold text-gray-800 mb-2">{report.incidentType}</h4>
            <div className="text-xs text-gray-600 mb-4 bg-gray-50 p-3 rounded-lg border italic">
              " {report.chronology} "
            </div>

            <div className="flex items-center justify-between pt-4 border-t gap-2">
              <div className="text-[10px] text-gray-400">Dilaporkan oleh: <span className="font-bold">{report.reporterName}</span> di <span className="font-bold">{report.location}</span></div>
              <div className="flex gap-1">
                {report.status === 'NEW' && <Button size="sm" variant="warning" onClick={() => onUpdateStatus(report.id, 'INVESTIGATING')}>Proses Investigasi</Button>}
                {report.status === 'INVESTIGATING' && <Button size="sm" variant="success" onClick={() => onUpdateStatus(report.id, 'RESOLVED')}>Selesaikan</Button>}
              </div>
            </div>
          </div>
        )) : (
          <div className="bg-white border-2 border-dashed rounded-xl p-12 text-center text-gray-400">
             Belum ada insiden yang dilaporkan.
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { DataManagement } from './components/Administrator/DataManagement';
import { FinanceModule } from './components/Administration/FinanceModule';
import { IncidentModule } from './components/Incidents/IncidentModule';
import { Button } from './components/Button';
import { INITIAL_MASTER_DATA } from './constants';
import { MasterData, User, Patient, SurgeryLog, FinanceRecord, IncidentReport } from './types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  LineChart, Line
} from 'recharts';
import { Plus, Users, Search, Filter, Calendar, Activity } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>({ 
    username: 'admin', 
    name: 'Admin Ruang Bedah', 
    role: 'SUPER_ADMIN', 
    position: 'Kepala Instalasi' 
  });
  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [masterData, setMasterData] = useState<MasterData>(INITIAL_MASTER_DATA);
  const [financeRecords, setFinanceRecords] = useState<FinanceRecord[]>([]);
  const [incidentReports, setIncidentReports] = useState<IncidentReport[]>([]);

  useEffect(() => {
    const savedMaster = localStorage.getItem('or_master_data');
    if (savedMaster) setMasterData(JSON.parse(savedMaster));

    const savedFinance = localStorage.getItem('or_finance');
    if (savedFinance) setFinanceRecords(JSON.parse(savedFinance));

    const savedIncidents = localStorage.getItem('or_incidents');
    if (savedIncidents) setIncidentReports(JSON.parse(savedIncidents));
  }, []);

  useEffect(() => {
    localStorage.setItem('or_finance', JSON.stringify(financeRecords));
  }, [financeRecords]);

  useEffect(() => {
    localStorage.setItem('or_incidents', JSON.stringify(incidentReports));
  }, [incidentReports]);

  const handleAddFinance = (rec: FinanceRecord) => setFinanceRecords([...financeRecords, rec]);
  const handleAddIncident = (rep: IncidentReport) => setIncidentReports([...incidentReports, rep]);
  const handleUpdateIncident = (id: string, status: IncidentReport['status']) => {
    setIncidentReports(incidentReports.map(r => r.id === id ? { ...r, status } : r));
  };

  const handleLogout = () => setUser(null);

  const renderContent = () => {
    switch (activeMenu) {
      case 'dashboard':
        return (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="bg-white p-6 rounded-xl border shadow-sm flex flex-col items-center">
                <div className="text-3xl font-bold text-blue-600 mb-1">12</div>
                <div className="text-xs text-gray-400 font-bold uppercase tracking-wider">Operasi Hari Ini</div>
              </div>
              <div className="bg-white p-6 rounded-xl border shadow-sm flex flex-col items-center">
                <div className="text-3xl font-bold text-emerald-600 mb-1">85%</div>
                <div className="text-xs text-gray-400 font-bold uppercase tracking-wider">BOR Bed Recovery</div>
              </div>
              <div className="bg-white p-6 rounded-xl border shadow-sm flex flex-col items-center">
                <div className="text-3xl font-bold text-amber-500 mb-1">
                  {incidentReports.filter(i => i.status === 'NEW').length}
                </div>
                <div className="text-xs text-gray-400 font-bold uppercase tracking-wider">Insiden Aktif</div>
              </div>
              <div className="bg-white p-6 rounded-xl border shadow-sm flex flex-col items-center">
                <div className="text-3xl font-bold text-purple-600 mb-1">100%</div>
                <div className="text-xs text-gray-400 font-bold uppercase tracking-wider">Kepatuhan Visite</div>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="bg-white p-6 rounded-xl border shadow-sm h-80">
                <h4 className="font-bold text-gray-700 mb-4 flex items-center gap-2"><Calendar size={18}/> Tren Volume Operasi</h4>
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={[
                    { name: 'Sen', val: 12 }, { name: 'Sel', val: 15 }, { name: 'Rab', val: 10 },
                    { name: 'Kam', val: 18 }, { name: 'Jum', val: 20 }, { name: 'Sab', val: 5 },
                  ]}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                    <XAxis dataKey="name" fontSize={12} />
                    <YAxis fontSize={12} />
                    <Tooltip />
                    <Line type="monotone" dataKey="val" stroke="#2563eb" strokeWidth={3} dot={{ r: 4 }} />
                  </LineChart>
                </ResponsiveContainer>
              </div>
              <div className="bg-white p-6 rounded-xl border shadow-sm h-80">
                <h4 className="font-bold text-gray-700 mb-4 flex items-center gap-2"><Activity size={18}/> Flow Kas Operasional</h4>
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={[
                    { name: 'Pendapatan', val: financeRecords.filter(f => f.type === 'INCOME').reduce((a,b) => a+b.amount, 0) },
                    { name: 'Pengeluaran', val: financeRecords.filter(f => f.type === 'EXPENSE').reduce((a,b) => a+b.amount, 0) }
                  ]}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                    <XAxis dataKey="name" fontSize={12} />
                    <YAxis fontSize={12} />
                    <Tooltip />
                    <Bar dataKey="val" fill="#2563eb" radius={[4, 4, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        );

      case 'admin-data':
        return <DataManagement masterData={masterData} onSave={(d) => setMasterData(d)} />;

      case 'adm-finance':
        return <FinanceModule records={financeRecords} onAddRecord={handleAddFinance} />;

      case 'inc-report':
        return <IncidentModule reports={incidentReports} onAddReport={handleAddIncident} onUpdateStatus={handleUpdateIncident} />;

      default:
        return (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 p-20 border-2 border-dashed rounded-3xl">
            <Activity size={64} className="mb-4 opacity-20"/>
            <p className="text-lg font-medium">Modul "{activeMenu}" sedang dalam pengembangan.</p>
            <p className="text-sm">Klik menu lain untuk mencoba fitur yang tersedia.</p>
          </div>
        );
    }
  };

  return (
    <Layout 
      user={user} 
      onLogout={handleLogout} 
      onNavigate={setActiveMenu} 
      activeMenu={activeMenu}
    >
      {renderContent()}
    </Layout>
  );
};

