import React, { useState } from 'react';
import { FinanceRecord, MasterData } from '../../types';
import { Button } from '../Button';
import { Plus, TrendingUp, TrendingDown, Wallet, Calendar, Search, Filter } from 'lucide-react';

interface FinanceModuleProps {
  records: FinanceRecord[];
  masterData: MasterData;
  onAddRecord: (record: FinanceRecord) => void;
}

export const FinanceModule: React.FC<FinanceModuleProps> = ({ records, masterData, onAddRecord }) => {
  const [showForm, setShowForm] = useState(false);
  const [period, setPeriod] = useState<'DAILY' | 'WEEKLY' | 'MONTHLY'>('MONTHLY');
  const [filterType, setFilterType] = useState<'ALL' | 'INCOME' | 'EXPENSE'>('ALL');

  const [newRecord, setNewRecord] = useState<Partial<FinanceRecord>>({
    type: 'INCOME',
    date: new Date().toISOString().split('T')[0],
    amount: 0,
    category: '',
    description: '',
    ksm: '',
    dpjp: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRecord.amount || !newRecord.category) return;

    onAddRecord({
      ...newRecord,
      id: Date.now().toString(),
      recordedBy: 'Admin'
    } as FinanceRecord);

    setShowForm(false);
    setNewRecord({ 
      type: 'INCOME', 
      date: new Date().toISOString().split('T')[0], 
      amount: 0, 
      category: '', 
      description: '',
      ksm: '',
      dpjp: ''
    });
  };

  const isInSelectedPeriod = (dateStr: string) => {
    const recordDate = new Date(dateStr);
    const today = new Date();

    if (period === 'DAILY') {
      return recordDate.toDateString() === today.toDateString();
    } else if (period === 'WEEKLY') {
      const oneWeekAgo = new Date();
      oneWeekAgo.setDate(today.getDate() - 7);
      return recordDate >= oneWeekAgo;
    } else { // Monthly
      return recordDate.getMonth() === today.getMonth() && recordDate.getFullYear() === today.getFullYear();
    }
  };

  const filteredRecords = records.filter(r => {
    const typeMatch = filterType === 'ALL' || r.type === filterType;
    return typeMatch && isInSelectedPeriod(r.date);
  });

  const totals = filteredRecords.reduce((acc, curr) => {
    if (curr.type === 'INCOME') acc.income += curr.amount;
    else acc.expense += curr.amount;
    return acc;
  }, { income: 0, expense: 0 });

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-white p-4 rounded-xl border shadow-sm">
        <h3 className="font-bold text-gray-800 flex items-center gap-2"><Wallet className="text-blue-600"/> Ringkasan Keuangan</h3>
        <div className="flex bg-gray-100 p-1 rounded-lg">
          {(['DAILY', 'WEEKLY', 'MONTHLY'] as const).map(p => (
            <button key={p} onClick={() => setPeriod(p)} className={`px-4 py-1.5 text-[10px] font-bold rounded-md transition-colors ${period === p ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>
              {p === 'DAILY' ? 'HARIAN' : p === 'WEEKLY' ? 'MINGGUAN' : 'BULANAN'}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-5 rounded-xl border shadow-sm border-l-4 border-l-emerald-500">
          <p className="text-[10px] font-bold text-gray-400 uppercase">Pendapatan ({period})</p>
          <h3 className="text-2xl font-bold text-emerald-600 mt-1">Rp {totals.income.toLocaleString('id-ID')}</h3>
        </div>
        <div className="bg-white p-5 rounded-xl border shadow-sm border-l-4 border-l-red-500">
          <p className="text-[10px] font-bold text-gray-400 uppercase">Pengeluaran ({period})</p>
          <h3 className="text-2xl font-bold text-red-600 mt-1">Rp {totals.expense.toLocaleString('id-ID')}</h3>
        </div>
        <div className="bg-white p-5 rounded-xl border shadow-sm border-l-4 border-l-blue-500">
          <p className="text-[10px] font-bold text-gray-400 uppercase">Saldo Bersih</p>
          <h3 className="text-2xl font-bold text-blue-600 mt-1">Rp {(totals.income - totals.expense).toLocaleString('id-ID')}</h3>
        </div>
      </div>

      <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
        <div className="p-4 border-b bg-gray-50 flex justify-between items-center">
          <div className="flex gap-2">
            <Button onClick={() => setShowForm(true)} size="sm"><Plus size={16} className="mr-2"/> Tambah Transaksi</Button>
            <select className="border rounded-lg px-3 py-1 text-xs" value={filterType} onChange={e => setFilterType(e.target.value as any)}>
              <option value="ALL">Semua Tipe</option>
              <option value="INCOME">Hanya Pendapatan</option>
              <option value="EXPENSE">Hanya Biaya</option>
            </select>
          </div>
          <span className="text-xs font-bold text-gray-400">{filteredRecords.length} Transaksi Ditemukan</span>
        </div>

        {showForm && (
          <div className="p-6 border-b bg-blue-50/30 animate-fade-in">
            <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Tipe & Kategori</label>
                <div className="flex gap-2">
                  <select className="flex-1 border rounded-lg p-2 text-sm" value={newRecord.type} onChange={e => setNewRecord({...newRecord, type: e.target.value as any})}>
                    <option value="INCOME">PENDAPATAN</option>
                    <option value="EXPENSE">PENGELUARAN</option>
                  </select>
                  <input className="flex-[2] border rounded-lg p-2 text-sm" placeholder="Kategori (misal: Visite)" value={newRecord.category} onChange={e => setNewRecord({...newRecord, category: e.target.value})}/>
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Jumlah (Rp)</label>
                <input type="number" className="w-full border rounded-lg p-2 text-sm font-bold" value={newRecord.amount} onChange={e => setNewRecord({...newRecord, amount: Number(e.target.value)})}/>
              </div>
              <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Tanggal</label>
                <input type="date" className="w-full border rounded-lg p-2 text-sm" value={newRecord.date} onChange={e => setNewRecord({...newRecord, date: e.target.value})}/>
              </div>

              {newRecord.type === 'INCOME' && (
                <>
                  <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">KSM / SMF (Opsional)</label>
                    <select className="w-full border rounded-lg p-2 text-sm" value={newRecord.ksm} onChange={e => setNewRecord({...newRecord, ksm: e.target.value})}>
                      <option value="">-- Pilih KSM --</option>
                      {masterData.refs.ksmList.map(k => <option key={k} value={k}>{k}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">DPJP (Opsional)</label>
                    <select className="w-full border rounded-lg p-2 text-sm" value={newRecord.dpjp} onChange={e => setNewRecord({...newRecord, dpjp: e.target.value})}>
                      <option value="">-- Pilih Dokter --</option>
                      {masterData.doctors.map(d => <option key={d} value={d}>{d}</option>)}
                    </select>
                  </div>
                </>
              )}
              <div className={newRecord.type === 'INCOME' ? "col-span-1" : "col-span-3"}>
                <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Keterangan</label>
                <input className="w-full border rounded-lg p-2 text-sm" value={newRecord.description} onChange={e => setNewRecord({...newRecord, description: e.target.value})}/>
              </div>

              <div className="col-span-3 flex justify-end gap-2 pt-2">
                <Button type="button" variant="secondary" size="sm" onClick={() => setShowForm(false)}>Batal</Button>
                <Button type="submit" size="sm">Simpan Transaksi</Button>
              </div>
            </form>
          </div>
        )}

        <div className="overflow-x-auto">
          <table className="w-full text-xs text-left">
            <thead className="bg-gray-100 text-gray-500 font-bold uppercase border-b">
              <tr>
                <th className="p-4">Tanggal</th>
                <th className="p-4">Kategori / KSM</th>
                <th className="p-4">DPJP</th>
                <th className="p-4 text-right">Jumlah</th>
                <th className="p-4 text-center">Tipe</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {filteredRecords.sort((a,b) => b.date.localeCompare(a.date)).map(r => (
                <tr key={r.id} className="hover:bg-gray-50">
                  <td className="p-4 font-medium">{r.date}</td>
                  <td className="p-4">
                    <div className="font-bold">{r.category}</div>
                    <div className="text-[10px] text-gray-400">{r.ksm || '-'}</div>
                  </td>
                  <td className="p-4 text-gray-500">{r.dpjp || '-'}</td>
                  <td className={`p-4 text-right font-bold ${r.type === 'INCOME' ? 'text-emerald-600' : 'text-red-600'}`}>
                    {r.type === 'INCOME' ? '+' : '-'} Rp {r.amount.toLocaleString('id-ID')}
                  </td>
                  <td className="p-4 text-center">
                    <span className={`px-2 py-0.5 rounded text-[10px] font-bold border ${r.type === 'INCOME' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-red-50 text-red-700 border-red-200'}`}>
                      {r.type}
                    </span>
                  </td>
                </tr>
              ))}
              {filteredRecords.length === 0 && (
                <tr><td colSpan={5} className="p-12 text-center text-gray-400 italic">Tidak ada catatan keuangan di periode ini.</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { DataManagement } from './components/Administrator/DataManagement';
import { FinanceModule } from './components/Administration/FinanceModule';
import { IncidentModule } from './components/Incidents/IncidentModule';
import { Button } from './components/Button';
import { INITIAL_DATA } from './constants';
import { AppData, User, FinanceRecord, IncidentReport } from './types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  LineChart, Line
} from 'recharts';
import { Activity, Wallet, AlertCircle, Calendar, Plus, Search, Filter } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>({ 
    username: 'administrator', 
    name: 'Super User', 
    role: 'SUPER_ADMIN', 
    position: 'Super User' 
  });
  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [appData, setAppData] = useState<AppData>(INITIAL_DATA);

  useEffect(() => {
    const saved = localStorage.getItem('or_manager_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Merge saved data with INITIAL_DATA structure to ensure new fields are present
      setAppData(prev => ({
        ...INITIAL_DATA,
        ...parsed,
        masterData: {
          ...INITIAL_DATA.masterData,
          ...parsed.masterData
        }
      }));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('or_manager_data', JSON.stringify(appData));
  }, [appData]);

  const handleAddFinance = (rec: FinanceRecord) => {
    setAppData(prev => ({
      ...prev,
      financeRecords: [...(prev.financeRecords || []), rec]
    }));
  };

  const handleAddIncident = (rep: IncidentReport) => {
    setAppData(prev => ({
      ...prev,
      incidentReports: [...(prev.incidentReports || []), rep]
    }));
  };

  const handleUpdateIncident = (id: string, status: IncidentReport['status']) => {
    setAppData(prev => ({
      ...prev,
      incidentReports: (prev.incidentReports || []).map(r => r.id === id ? { ...r, status } : r)
    }));
  };

  const handleLogout = () => setUser(null);

  const renderContent = () => {
    const financeRecords = appData.financeRecords || [];
    const incidentReports = appData.incidentReports || [];

    switch (activeMenu) {
      case 'dashboard':
        return (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="bg-white p-6 rounded-xl border shadow-sm flex flex-col items-center">
                <div className="text-3xl font-bold text-blue-600 mb-1">0</div>
                <div className="text-xs text-gray-400 font-bold uppercase tracking-wider">Operasi Hari Ini</div>
              </div>
              <div className="bg-white p-6 rounded-xl border shadow-sm flex flex-col items-center">
                <div className="text-3xl font-bold text-emerald-600 mb-1">0%</div>
                <div className="text-xs text-gray-400 font-bold uppercase tracking-wider">BOR Ruang Bedah</div>
              </div>
              <div className="bg-white p-6 rounded-xl border shadow-sm flex flex-col items-center">
                <div className="text-3xl font-bold text-amber-500 mb-1">
                  {incidentReports.filter(i => i.status !== 'RESOLVED').length}
                </div>
                <div className="text-xs text-gray-400 font-bold uppercase tracking-wider">Insiden Terbuka</div>
              </div>
              <div className="bg-white p-6 rounded-xl border shadow-sm flex flex-col items-center">
                <div className="text-3xl font-bold text-purple-600 mb-1">100%</div>
                <div className="text-xs text-gray-400 font-bold uppercase tracking-wider">Visite Selesai</div>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="bg-white p-6 rounded-xl border shadow-sm h-80">
                <h4 className="font-bold text-gray-700 mb-4 flex items-center gap-2"><Wallet size={18}/> Status Keuangan (Akumulasi)</h4>
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={[
                    { name: 'In', val: financeRecords.filter(f => f.type === 'INCOME').reduce((a,b) => a+b.amount, 0) },
                    { name: 'Out', val: financeRecords.filter(f => f.type === 'EXPENSE').reduce((a,b) => a+b.amount, 0) }
                  ]}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                    <XAxis dataKey="name" fontSize={12} />
                    <YAxis fontSize={12} />
                    <Tooltip />
                    <Bar dataKey="val" fill="#2563eb" radius={[4, 4, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
              <div className="bg-white p-6 rounded-xl border shadow-sm overflow-hidden flex flex-col">
                <h4 className="font-bold text-gray-700 mb-4 flex items-center gap-2"><AlertCircle size={18} className="text-red-500"/> Insiden Terbaru</h4>
                <div className="flex-1 overflow-y-auto space-y-2">
                  {incidentReports.length > 0 ? incidentReports.slice(-5).reverse().map(i => (
                    <div key={i.id} className="p-3 bg-gray-50 rounded-lg border flex justify-between items-center">
                      <div>
                        <div className="text-xs font-bold text-gray-800">{i.incidentType}</div>
                        <div className="text-[10px] text-gray-400">{i.date} | {i.location}</div>
                      </div>
                      <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border ${i.status === 'NEW' ? 'bg-red-50 text-red-600 border-red-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>{i.status}</span>
                    </div>
                  )) : <div className="text-center text-gray-400 text-xs py-10">Belum ada data insiden</div>}
                </div>
              </div>
            </div>
          </div>
        );

      case 'admin-data':
        return <DataManagement masterData={appData.masterData} onSave={(d) => setAppData({...appData, masterData: d})} />;

      case 'adm-finance':
        return <FinanceModule records={financeRecords} masterData={appData.masterData} onAddRecord={handleAddFinance} />;

      case 'inc-report':
        return <IncidentModule reports={incidentReports} onAddReport={handleAddIncident} onUpdateStatus={handleUpdateIncident} />;

      default:
        return (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 p-20 border-2 border-dashed rounded-3xl">
            <Activity size={64} className="mb-4 opacity-20"/>
            <p className="text-lg font-medium">Modul "{activeMenu}" sedang dalam pengembangan.</p>
            <p className="text-sm">Klik menu lain untuk mencoba fitur yang tersedia.</p>
          </div>
        );
    }
  };

  return (
    <Layout user={user} onLogout={handleLogout} onNavigate={setActiveMenu} activeMenu={activeMenu}>
      {renderContent()}
    </Layout>
  );
};

