};

import React, { useState } from 'react';
import { IncidentReport } from '../../types';
import { Button } from '../Button';
import { AlertCircle, Plus, CheckCircle2, Clock, ShieldAlert, Send, Bell } from 'lucide-react';

interface IncidentModuleProps {
  reports: IncidentReport[];
  onAddReport: (report: IncidentReport) => void;
  onUpdateStatus: (id: string, status: IncidentReport['status'], notes?: string) => void;
}

export const IncidentModule: React.FC<IncidentModuleProps> = ({ reports, onAddReport, onUpdateStatus }) => {
  const [showForm, setShowForm] = useState(false);
  const [activeNotification, setActiveNotification] = useState<string | null>(null);
  const [newReport, setNewReport] = useState<Partial<IncidentReport>>({
    severity: 'YELLOW',
    incidentType: '',
    location: '',
    chronology: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const report: IncidentReport = {
      ...newReport,
      id: Date.now().toString(),
      date: new Date().toISOString().split('T')[0],
      time: new Date().toTimeString().split(' ')[0],
      reporterName: 'Petugas Bedah',
      status: 'NEW',
    } as IncidentReport;

    onAddReport(report);
    setShowForm(false);

    // Simulate Notification
    setActiveNotification(`NOTIFIKASI PIC: Insiden "${report.incidentType}" baru saja dilaporkan!`);
    setTimeout(() => setActiveNotification(null), 8000);
  };

  const severityStyles = {
    GREEN: 'bg-emerald-100 text-emerald-700 border-emerald-200',
    YELLOW: 'bg-amber-100 text-amber-700 border-amber-200',
    RED: 'bg-red-100 text-red-700 border-red-200'
  };

  const statusIcons = {
    NEW: <Clock size={16} className="text-red-500" />,
    INVESTIGATING: <AlertCircle size={16} className="text-amber-500" />,
    RESOLVED: <CheckCircle2 size={16} className="text-emerald-500" />
  };

  return (
    <div className="space-y-4">
      {activeNotification && (
        <div className="bg-slate-900 text-white p-4 rounded-xl shadow-2xl flex items-center justify-between animate-fade-in border-l-4 border-l-blue-400">
          <div className="flex items-center gap-3">
            <Bell className="text-blue-400 animate-bounce" size={20}/>
            <p className="text-sm font-bold tracking-tight">{activeNotification}</p>
          </div>
          <button onClick={() => setActiveNotification(null)} className="text-white opacity-50 hover:opacity-100 font-bold">Tutup</button>
        </div>
      )}

      <div className="flex justify-between items-center bg-white p-4 rounded-xl border shadow-sm">
        <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800">
          <ShieldAlert className="text-red-600"/> Pelacakan Insiden (PIC)
        </h3>
        <Button onClick={() => setShowForm(!showForm)} size="sm">
          <Plus size={16} className="mr-2"/> Buat Laporan Baru
        </Button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-xl border-2 border-red-100 shadow-lg animate-fade-in">
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="col-span-2">
              <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Judul Insiden</label>
              <input required className="w-full border rounded-lg p-3 text-sm" placeholder="Contoh: Salah pemberian obat, Pasien jatuh..." value={newReport.incidentType} onChange={e => setNewReport({...newReport, incidentType: e.target.value})}/>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Lokasi Kejadian</label>
              <input required className="w-full border rounded-lg p-3 text-sm" placeholder="Misal: OK Utama, Ruang Pulih..." value={newReport.location} onChange={e => setNewReport({...newReport, location: e.target.value})}/>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Tingkat Bahaya</label>
              <select className="w-full border rounded-lg p-3 text-sm" value={newReport.severity} onChange={e => setNewReport({...newReport, severity: e.target.value as any})}>
                <option value="GREEN">GREEN (Ringan)</option>
                <option value="YELLOW">YELLOW (Sedang)</option>
                <option value="RED">RED (Berat / Sentinel)</option>
              </select>
            </div>
            <div className="col-span-2">
              <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Kronologi Kejadian</label>
              <textarea required className="w-full border rounded-lg p-3 text-sm min-h-[120px]" placeholder="Jabarkan apa yang terjadi..." value={newReport.chronology} onChange={e => setNewReport({...newReport, chronology: e.target.value})}/>
            </div>
            <div className="col-span-2 flex justify-end gap-2">
              <Button type="button" variant="secondary" onClick={() => setShowForm(false)}>Batal</Button>
              <Button type="submit" variant="danger"><Send size={16} className="mr-2"/> Kirim ke PIC</Button>
            </div>
          </form>
        </div>
      )}

      <div className="space-y-4">
        {reports.length > 0 ? reports.sort((a,b) => b.date.localeCompare(a.date)).map(report => (
          <div key={report.id} className="bg-white border rounded-xl p-5 shadow-sm hover:shadow-md transition-shadow relative overflow-hidden">
            <div className="flex justify-between items-start mb-4">
              <div className="flex items-center gap-3">
                <span className={`px-3 py-1 rounded text-[10px] font-bold border ${severityStyles[report.severity]}`}>
                  SEVERITY: {report.severity}
                </span>
                <span className="text-xs text-gray-400 font-medium">{report.date} • {report.time}</span>
              </div>
              <div className="flex items-center gap-2 bg-gray-50 px-3 py-1 rounded-full border">
                {statusIcons[report.status]}
                <span className="text-[10px] font-bold text-gray-600 uppercase">{report.status.replace('_', ' ')}</span>
              </div>
            </div>

            <h4 className="font-bold text-gray-800 text-lg mb-2">{report.incidentType}</h4>
            <div className="bg-gray-50 p-3 rounded-lg border border-dashed text-xs text-gray-600 mb-4 italic">
              " {report.chronology} "
            </div>

            <div className="flex items-center justify-between pt-4 border-t">
              <div className="text-[10px] text-gray-400">Reporter: <span className="font-bold">{report.reporterName}</span> | Lokasi: <span className="font-bold">{report.location}</span></div>
              <div className="flex gap-2">
                {report.status === 'NEW' && (
                  <Button size="sm" variant="warning" onClick={() => onUpdateStatus(report.id, 'INVESTIGATING')}>Mulai Investigasi</Button>
                )}
                {report.status === 'INVESTIGATING' && (
                  <Button size="sm" variant="success" onClick={() => onUpdateStatus(report.id, 'RESOLVED')}>Selesaikan Penanganan</Button>
                )}
                {report.status === 'RESOLVED' && (
                  <div className="flex items-center gap-1 text-emerald-600 text-[10px] font-bold">
                    <CheckCircle2 size={16}/> SELESAI DITANGANI
                  </div>
                )}
              </div>
            </div>
          </div>
        )) : (
          <div className="bg-white border-2 border-dashed rounded-xl p-16 text-center">
             <ShieldAlert className="mx-auto text-gray-200 mb-2" size={48}/>
             <p className="text-gray-400 text-sm">Belum ada data insiden yang dilaporkan.</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { DataManagement } from './components/Administrator/DataManagement';
import { FinanceModule } from './components/Administration/FinanceModule';
import { IncidentModule } from './components/Incidents/IncidentModule';
import { Button } from './components/Button';
import { INITIAL_DATA } from './constants';
import { AppData, User, FinanceRecord, IncidentReport } from './types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  LineChart, Line, Cell
} from 'recharts';
import { Activity, Wallet, AlertCircle, Calendar, Plus, Search, Filter, TrendingUp, Users } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>({ 
    username: 'administrator', 
    name: 'Super User', 
    role: 'SUPER_ADMIN', 
    position: 'Super User' 
  });
  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [appData, setAppData] = useState<AppData>(INITIAL_DATA);

  useEffect(() => {
    const saved = localStorage.getItem('or_manager_data_v2');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Data merging strategy
      setAppData(prev => ({
        ...INITIAL_DATA,
        ...parsed,
        masterData: {
          ...INITIAL_DATA.masterData,
          ...parsed.masterData
        }
      }));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('or_manager_data_v2', JSON.stringify(appData));
  }, [appData]);

  const handleAddFinance = (rec: FinanceRecord) => {
    setAppData(prev => ({
      ...prev,
      financeRecords: [...(prev.financeRecords || []), rec]
    }));
  };

  const handleAddIncident = (rep: IncidentReport) => {
    setAppData(prev => ({
      ...prev,
      incidentReports: [...(prev.incidentReports || []), rep]
    }));
  };

  const handleUpdateIncident = (id: string, status: IncidentReport['status']) => {
    setAppData(prev => ({
      ...prev,
      incidentReports: (prev.incidentReports || []).map(r => r.id === id ? { ...r, status } : r)
    }));
  };

  const handleLogout = () => setUser(null);

  const renderContent = () => {
    const financeRecords = appData.financeRecords || [];
    const incidentReports = appData.incidentReports || [];

    switch (activeMenu) {
      case 'dashboard':
        return (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="bg-white p-6 rounded-xl border shadow-sm border-t-4 border-t-blue-500">
                <div className="text-3xl font-bold text-slate-800 mb-1">0</div>
                <div className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Operasi Harian</div>
              </div>
              <div className="bg-white p-6 rounded-xl border shadow-sm border-t-4 border-t-emerald-500">
                <div className="text-3xl font-bold text-emerald-600 mb-1">
                  Rp {(financeRecords.filter(f => f.type === 'INCOME').reduce((a, b) => a + b.amount, 0) / 1000000).toFixed(1)}M
                </div>
                <div className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Pendapatan Bulan Ini</div>
              </div>
              <div className="bg-white p-6 rounded-xl border shadow-sm border-t-4 border-t-amber-500">
                <div className="text-3xl font-bold text-amber-500 mb-1">
                  {incidentReports.filter(i => i.status !== 'RESOLVED').length}
                </div>
                <div className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Insiden Terbuka</div>
              </div>
              <div className="bg-white p-6 rounded-xl border shadow-sm border-t-4 border-t-indigo-500">
                <div className="text-3xl font-bold text-indigo-600 mb-1">{appData.masterData.doctors.length}</div>
                <div className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Total DPJP Terdaftar</div>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-2 bg-white p-6 rounded-xl border shadow-sm h-96 flex flex-col">
                <div className="flex justify-between items-center mb-6">
                  <h4 className="font-bold text-gray-700 flex items-center gap-2"><TrendingUp size={18} className="text-emerald-500"/> Performance Finansial</h4>
                  <div className="text-[10px] font-bold text-gray-400">AKUMULASI TRANSAKSI</div>
                </div>
                <div className="flex-1">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={[
                      { name: 'Income', val: financeRecords.filter(f => f.type === 'INCOME').reduce((a,b) => a+b.amount, 0) },
                      { name: 'Expense', val: financeRecords.filter(f => f.type === 'EXPENSE').reduce((a,b) => a+b.amount, 0) }
                    ]}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} opacity={0.3} />
                      <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} />
                      <YAxis fontSize={12} tickLine={false} axisLine={false} tickFormatter={(v) => `Rp ${v/1000000}M`} />
                      <Tooltip formatter={(v) => `Rp ${v.toLocaleString('id-ID')}`} />
                      <Bar dataKey="val" radius={[4, 4, 0, 0]}>
                        <Cell fill="#10b981" />
                        <Cell fill="#ef4444" />
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </div>

              <div className="bg-white p-6 rounded-xl border shadow-sm flex flex-col overflow-hidden">
                <div className="flex justify-between items-center mb-6">
                  <h4 className="font-bold text-gray-700 flex items-center gap-2"><AlertCircle size={18} className="text-red-500"/> Antrian Insiden</h4>
                  <span className="bg-red-50 text-red-600 text-[10px] font-bold px-2 py-0.5 rounded border border-red-100">PIC ALERTS</span>
                </div>
                <div className="flex-1 overflow-y-auto space-y-3">
                  {incidentReports.length > 0 ? incidentReports.slice(-6).reverse().map(i => (
                    <div key={i.id} className="p-3 bg-gray-50 rounded-lg border border-gray-100 flex items-start gap-3">
                      <div className={`mt-1 w-2 h-2 rounded-full shrink-0 ${i.status === 'NEW' ? 'bg-red-500 animate-pulse' : i.status === 'INVESTIGATING' ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
                      <div className="flex-1 min-w-0">
                        <div className="text-xs font-bold text-gray-800 truncate">{i.incidentType}</div>
                        <div className="text-[10px] text-gray-400">{i.location} • {i.date}</div>
                      </div>
                    </div>
                  )) : (
                    <div className="h-full flex flex-col items-center justify-center text-gray-300">
                      <ShieldAlert size={48} className="opacity-20 mb-2"/>
                      <p className="text-[10px] font-bold uppercase tracking-widest">No Active Incidents</p>
                    </div>
                  )}
                </div>
                <Button variant="ghost" size="sm" className="mt-4 w-full text-[10px] font-bold" onClick={() => setActiveMenu('inc-report')}>Lihat Semua Laporan</Button>
              </div>
            </div>
          </div>
        );

      case 'admin-data':
        return <DataManagement masterData={appData.masterData} onSave={(d) => setAppData({...appData, masterData: d})} />;

      case 'adm-finance':
        return <FinanceModule records={financeRecords} masterData={appData.masterData} onAddRecord={handleAddFinance} />;

      case 'inc-report':
        return <IncidentModule reports={incidentReports} onAddReport={handleAddIncident} onUpdateStatus={handleUpdateIncident} />;

      default:
        return (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 p-20 border-2 border-dashed rounded-3xl">
            <Activity size={64} className="mb-4 opacity-20"/>
            <p className="text-lg font-medium">Modul "{activeMenu}" sedang dalam pengembangan.</p>
            <p className="text-sm">Klik menu lain untuk mencoba fitur yang tersedia.</p>
          </div>
        );
    }
  };

  return (
    <Layout user={user} onLogout={handleLogout} onNavigate={setActiveMenu} activeMenu={activeMenu}>
      {renderContent()}
    </Layout>
  );
};

export default App;

