import React, { useState } from 'react';
import { IncidentReport } from '../../types';
import { Button } from '../Button';
import { AlertCircle, Plus, CheckCircle2, Clock, ShieldAlert, Send, Bell, Filter, Search, MoreVertical } from 'lucide-react';

interface IncidentModuleProps {
  reports: IncidentReport[];
  onAddReport: (report: IncidentReport) => void;
  onUpdateStatus: (id: string, status: IncidentReport['status'], notes?: string) => void;
}

export const IncidentModule: React.FC<IncidentModuleProps> = ({ reports, onAddReport, onUpdateStatus }) => {
  const [showForm, setShowForm] = useState(false);
  const [activeNotification, setActiveNotification] = useState<string | null>(null);
  const [newReport, setNewReport] = useState<Partial<IncidentReport>>({
    severity: 'YELLOW',
    incidentType: '',
    location: '',
    chronology: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newReport.incidentType || !newReport.chronology) return;

    const report: IncidentReport = {
      ...newReport,
      id: Date.now().toString(),
      date: new Date().toISOString().split('T')[0],
      time: new Date().toTimeString().split(' ')[0],
      reporterName: 'User Perawat',
      status: 'NEW',
    } as IncidentReport;

    onAddReport(report);
    setShowForm(false);

    // Simulate Notification for PIC
    setActiveNotification(`URGENT: Insiden "${report.incidentType}" baru saja dilaporkan. PIC telah diberitahu!`);
    setTimeout(() => setActiveNotification(null), 10000);
  };

  const severityStyles = {
    GREEN: 'bg-emerald-100 text-emerald-700 border-emerald-200',
    YELLOW: 'bg-amber-100 text-amber-700 border-amber-200',
    RED: 'bg-red-100 text-red-700 border-red-200'
  };

  const statusIcons = {
    NEW: <Clock size={16} className="text-red-500" />,
    INVESTIGATING: <AlertCircle size={16} className="text-amber-500" />,
    RESOLVED: <CheckCircle2 size={16} className="text-emerald-500" />
  };

  return (
    <div className="space-y-4 max-w-5xl mx-auto">
      {activeNotification && (
        <div className="bg-slate-900 text-white p-5 rounded-2xl shadow-2xl flex items-center justify-between animate-fade-in border-l-8 border-l-blue-500 fixed top-6 right-6 z-50 w-full max-w-md">
          <div className="flex items-center gap-4">
            <div className="bg-blue-500/20 p-2 rounded-full"><Bell className="text-blue-400 animate-bounce" size={24}/></div>
            <div>
              <p className="text-[10px] font-black uppercase tracking-widest text-blue-400">Peringatan Sistem</p>
              <p className="text-xs font-bold leading-relaxed">{activeNotification}</p>
            </div>
          </div>
          <button onClick={() => setActiveNotification(null)} className="p-2 hover:bg-white/10 rounded-lg text-white opacity-50 hover:opacity-100 transition-all"><X size={18}/></button>
        </div>
      )}

      <div className="bg-white p-6 rounded-2xl border shadow-sm flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-2xl font-black flex items-center gap-2 text-slate-800">
            <ShieldAlert className="text-red-600" size={28}/> Pelaporan & Pelacakan Insiden
          </h3>
          <p className="text-xs text-gray-400">Pastikan setiap insiden KPRS dilaporkan <span className="text-red-500 font-bold">sebelum 2x24 jam</span>.</p>
        </div>
        <Button onClick={() => setShowForm(!showForm)} size="md" className="px-8 rounded-full shadow-lg shadow-blue-200">
          <Plus size={18} className="mr-2"/> Laporkan Insiden Baru
        </Button>
      </div>

      {showForm && (
        <div className="bg-white p-8 rounded-2xl border-2 border-red-100 shadow-2xl animate-fade-in">
          <div className="flex justify-between items-center mb-6">
            <h4 className="font-black text-slate-800 text-lg flex items-center gap-2"><Send className="text-red-500"/> Form Laporan Insiden KPRS</h4>
            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter">KERAHASIAAN TERJAMIN</span>
          </div>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="col-span-2">
              <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Judul Singkat Insiden</label>
              <input required className="w-full border rounded-xl p-3 text-sm focus:ring-2 focus:ring-red-500 focus:border-red-500 outline-none transition-all" placeholder="Contoh: Salah identitas pasien, Reaksi transfusi berat..." value={newReport.incidentType} onChange={e => setNewReport({...newReport, incidentType: e.target.value})}/>
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Lokasi Kejadian</label>
              <input required className="w-full border rounded-xl p-3 text-sm focus:ring-2 focus:ring-red-500 outline-none" placeholder="Misal: Kamar Operasi 02, RR..." value={newReport.location} onChange={e => setNewReport({...newReport, location: e.target.value})}/>
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Tingkat Risiko (Severity)</label>
              <select className="w-full border rounded-xl p-3 text-sm focus:ring-2 focus:ring-red-500 outline-none appearance-none bg-white" value={newReport.severity} onChange={e => setNewReport({...newReport, severity: e.target.value as any})}>
                <option value="GREEN">HIJAU (Cedera Ringan / Nyaris Cedera)</option>
                <option value="YELLOW">KUNING (Cedera Sedang / Reversibel)</option>
                <option value="RED">MERAH (SENTINEL / Kematian / Cacat Permanen)</option>
              </select>
            </div>
            <div className="col-span-2">
              <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Kronologi Kejadian & Dampak</label>
              <textarea required className="w-full border rounded-xl p-4 text-sm min-h-[140px] focus:ring-2 focus:ring-red-500 outline-none leading-relaxed" placeholder="Jabarkan secara objektif: Kapan, Siapa, Apa, Bagaimana..." value={newReport.chronology} onChange={e => setNewReport({...newReport, chronology: e.target.value})}/>
            </div>
            <div className="col-span-2 flex justify-end gap-3 pt-4 border-t">
              <Button type="button" variant="secondary" onClick={() => setShowForm(false)} className="px-8 rounded-full">Batal</Button>
              <Button type="submit" variant="danger" className="px-12 rounded-full shadow-lg shadow-red-200">Kirim Laporan & Alert PIC</Button>
            </div>
          </form>
        </div>
      )}

      <div className="flex flex-col gap-4">
        {reports.length > 0 ? (
          <div className="grid grid-cols-1 gap-4">
            {reports.sort((a,b) => b.date.localeCompare(a.date)).map(report => (
              <div key={report.id} className="bg-white border rounded-2xl p-6 shadow-sm hover:shadow-md transition-all group">
                <div className="flex justify-between items-start mb-4">
                  <div className="flex items-center gap-3">
                    <span className={`px-4 py-1.5 rounded-full text-[10px] font-black border ${severityStyles[report.severity]}`}>
                      RISIKO: {report.severity}
                    </span>
                    <span className="text-xs text-gray-400 font-bold">{report.date} • {report.time}</span>
                  </div>
                  <div className="flex items-center gap-2 bg-gray-50 px-4 py-1.5 rounded-full border group-hover:border-blue-200 transition-colors">
                    {statusIcons[report.status]}
                    <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">{report.status.replace('_', ' ')}</span>
                  </div>
                </div>

                <h4 className="font-black text-slate-800 text-xl mb-3 tracking-tight">{report.incidentType}</h4>
                <div className="bg-slate-50 p-4 rounded-xl border border-dashed border-slate-200 text-xs text-slate-600 mb-6 leading-relaxed relative">
                   <span className="absolute -top-3 left-3 bg-white px-2 text-[9px] font-black text-slate-400 border rounded">KRONOLOGI</span>
                  " {report.chronology} "
                </div>

                <div className="flex flex-col md:flex-row items-center justify-between gap-4 pt-4 border-t border-slate-100">
                  <div className="text-[10px] text-gray-400 flex items-center gap-4">
                    <span>Pelapor: <span className="font-bold text-slate-700">{report.reporterName}</span></span>
                    <span className="w-1 h-1 bg-gray-300 rounded-full"></span>
                    <span>Lokasi: <span className="font-bold text-slate-700">{report.location}</span></span>
                  </div>
                  <div className="flex gap-2 w-full md:w-auto">
                    {report.status === 'NEW' && (
                      <Button size="sm" variant="warning" onClick={() => onUpdateStatus(report.id, 'INVESTIGATING')} className="flex-1 md:flex-none px-6 rounded-full font-black text-[10px]">Tindak Lanjut Investigasi</Button>
                    )}
                    {report.status === 'INVESTIGATING' && (
                      <Button size="sm" variant="success" onClick={() => onUpdateStatus(report.id, 'RESOLVED')} className="flex-1 md:flex-none px-6 rounded-full font-black text-[10px]">Tandai Selesai & Resolved</Button>
                    )}
                    {report.status === 'RESOLVED' && (
                      <div className="flex items-center gap-2 text-emerald-600 text-[10px] font-black bg-emerald-50 px-4 py-2 rounded-full border border-emerald-100">
                        <CheckCircle2 size={16}/> CASE RESOLVED & CLOSED
                      </div>
                    )}
                    <button className="p-2 text-gray-300 hover:text-gray-600 transition-colors"><MoreVertical size={18}/></button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="bg-white border-2 border-dashed rounded-3xl p-24 text-center flex flex-col items-center justify-center grayscale opacity-30">
             <ShieldAlert size={80} className="mb-4 text-gray-300"/>
             <p className="text-xl font-black text-gray-400 uppercase tracking-[0.2em]">Zero Incidents Logged</p>
             <p className="text-sm text-gray-300 mt-2">Semua sistem dalam kondisi aman dan terkendali.</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { DataManagement } from './components/Administrator/DataManagement';
import { FinanceModule } from './components/Administration/FinanceModule';
import { IncidentModule } from './components/Incidents/IncidentModule';
import { Button } from './components/Button';
import { INITIAL_DATA } from './constants';
import { AppData, User, FinanceRecord, IncidentReport } from './types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  Cell, PieChart, Pie
} from 'recharts';
import { Activity, Wallet, AlertCircle, Calendar, Plus, Search, Filter, TrendingUp, Users, ShieldAlert, BarChart3, Clock } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>({ 
    username: 'administrator', 
    name: 'Super User', 
    role: 'SUPER_ADMIN', 
    position: 'Super User' 
  });
  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [appData, setAppData] = useState<AppData>(INITIAL_DATA);

  useEffect(() => {
    const saved = localStorage.getItem('or_manager_v3_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      setAppData(prev => ({
        ...INITIAL_DATA,
        ...parsed,
        masterData: {
          ...INITIAL_DATA.masterData,
          ...parsed.masterData
        }
      }));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('or_manager_v3_data', JSON.stringify(appData));
  }, [appData]);

  const handleAddFinance = (rec: FinanceRecord) => {
    setAppData(prev => ({
      ...prev,
      financeRecords: [...(prev.financeRecords || []), rec]
    }));
  };

  const handleAddIncident = (rep: IncidentReport) => {
    setAppData(prev => ({
      ...prev,
      incidentReports: [...(prev.incidentReports || []), rep]
    }));
  };

  const handleUpdateIncident = (id: string, status: IncidentReport['status']) => {
    setAppData(prev => ({
      ...prev,
      incidentReports: (prev.incidentReports || []).map(r => r.id === id ? { ...r, status } : r)
    }));
  };

  const handleLogout = () => setUser(null);

  const renderContent = () => {
    const financeRecords = appData.financeRecords || [];
    const incidentReports = appData.incidentReports || [];
    const openIncidents = incidentReports.filter(i => i.status !== 'RESOLVED');

    switch (activeMenu) {
      case 'dashboard':
        return (
          <div className="space-y-6 animate-fade-in">
            {/* TOP STATS */}
