                    </div>
                  )}
                </div>
                <button 
                  onClick={() => setActiveMenu('inc-report')}
                  className="mt-6 w-full py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-slate-800 transition-colors shadow-lg shadow-slate-200"
                >
                  Buka Modul Insiden
                </button>
              </div>
            </div>
          </div>
        );

      case 'admin-data':
        return <DataManagement masterData={appData.masterData} onSave={(d) => setAppData({...appData, masterData: d})} />;

      case 'adm-finance':
        return <FinanceModule records={financeRecords} masterData={appData.masterData} onAddRecord={handleAddFinance} />;

      case 'inc-report':
        return <IncidentModule reports={incidentReports} onAddReport={handleAddIncident} onUpdateStatus={handleUpdateIncident} />;

      default:
        return (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 p-24 bg-white rounded-3xl border-2 border-dashed">
