          </div>
        );
    }
  };

  return (
    <Layout 
      user={user} 
      onLogout={handleLogout} 
      onNavigate={setActiveMenu} 
      activeMenu={activeMenu}
    >
      {renderContent()}
    </Layout>
  );
};

