            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter">KERAHASIAAN TERJAIN</span>
          </div>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="col-span-2">
              <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Judul Singkat Insiden</label>
              <input required className="w-full border rounded-xl p-3 text-sm focus:ring-2 focus:ring-red-500 focus:border-red-500 outline-none transition-all" placeholder="Contoh: Salah identitas pasien, Reaksi transfusi berat..." value={newReport.incidentType} onChange={e => setNewReport({...newReport, incidentType: e.target.value})}/>
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Lokasi Kejadian</label>
              <input required className="w-full border rounded-xl p-3 text-sm focus:ring-2 focus:ring-red-500 outline-none" placeholder="Misal: Kamar Operasi 02, RR..." value={newReport.location} onChange={e => setNewReport({...newReport, location: e.target.value})}/>
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Tingkat Risiko (Severity)</label>
              <select className="w-full border rounded-xl p-3 text-sm focus:ring-2 focus:ring-red-500 outline-none appearance-none bg-white" value={newReport.severity} onChange={e => setNewReport({...newReport, severity: e.target.value as any})}>
                <option value="GREEN">HIJAU (Cedera Ringan / Nyaris Cedera)</option>
                <option value="YELLOW">KUNING (Cedera Sedang / Reversibel)</option>
                <option value="RED">MERAH (SENTINEL / Kematian / Cacat Permanen)</option>
              </select>
            </div>
            <div className="col-span-2">
              <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Kronologi Kejadian & Dampak</label>
              <textarea required className="w-full border rounded-xl p-4 text-sm min-h-[140px] focus:ring-2 focus:ring-red-500 outline-none leading-relaxed" placeholder="Jabarkan secara objektif: Kapan, Siapa, Apa, Bagaimana..." value={newReport.chronology} onChange={e => setNewReport({...newReport, chronology: e.target.value})}/>
            </div>
            <div className="col-span-2 flex justify-end gap-3 pt-4 border-t">
              <Button type="button" variant="secondary" onClick={() => setShowForm(false)} className="px-8 rounded-full">Batal</Button>
              <Button type="submit" variant="danger" className="px-12 rounded-full shadow-lg shadow-red-200">Kirim Laporan & Alert PIC</Button>
            </div>
          </form>
        </div>
      )}

      <div className="flex flex-col gap-4">
        {reports.length > 0 ? (
          <div className="grid grid-cols-1 gap-4">
            {reports.sort((a,b) => b.date.localeCompare(a.date)).map(report => (
              <div key={report.id} className="bg-white border rounded-2xl p-6 shadow-sm hover:shadow-md transition-all group">
                <div className="flex justify-between items-start mb-4">
                  <div className="flex items-center gap-3">
                    <span className={`px-4 py-1.5 rounded-full text-[10px] font-black border ${severityStyles[report.severity]}`}>
                      RISIKO: {report.severity}
                    </span>
                    <span className="text-xs text-gray-400 font-bold">{report.date} • {report.time}</span>
                  </div>
                  <div className="flex items-center gap-2 bg-gray-50 px-4 py-1.5 rounded-full border group-hover:border-blue-200 transition-colors">
                    {statusIcons[report.status]}
                    <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">{report.status.replace('_', ' ')}</span>
                  </div>
                </div>

                <h4 className="font-black text-slate-800 text-xl mb-3 tracking-tight">{report.incidentType}</h4>
                <div className="bg-slate-50 p-4 rounded-xl border border-dashed border-slate-200 text-xs text-slate-600 mb-6 leading-relaxed relative">
                   <span className="absolute -top-3 left-3 bg-white px-2 text-[9px] font-black text-slate-400 border rounded">KRONOLOGI</span>
                  " {report.chronology} "
                </div>

                <div className="flex flex-col md:flex-row items-center justify-between gap-4 pt-4 border-t border-slate-100">
                  <div className="text-[10px] text-gray-400 flex items-center gap-4">
                    <span>Pelapor: <span className="font-bold text-slate-700">{report.reporterName}</span></span>
                    <span className="w-1 h-1 bg-gray-300 rounded-full"></span>
                    <span>Lokasi: <span className="font-bold text-slate-700">{report.location}</span></span>
                  </div>
                  <div className="flex gap-2 w-full md:w-auto">
                    {report.status === 'NEW' && (
                      <Button size="sm" variant="warning" onClick={() => onUpdateStatus(report.id, 'INVESTIGATING')} className="flex-1 md:flex-none px-6 rounded-full font-black text-[10px]">Tindak Lanjut Investigasi</Button>
                    )}
                    {report.status === 'INVESTIGATING' && (
                      <Button size="sm" variant="success" onClick={() => onUpdateStatus(report.id, 'RESOLVED')} className="flex-1 md:flex-none px-6 rounded-full font-black text-[10px]">Tandai Selesai & Resolved</Button>
                    )}
                    {report.status === 'RESOLVED' && (
                      <div className="flex items-center gap-2 text-emerald-600 text-[10px] font-black bg-emerald-50 px-4 py-2 rounded-full border border-emerald-100">
                        <CheckCircle2 size={16}/> CASE RESOLVED & CLOSED
                      </div>
                    )}
                    <button className="p-2 text-gray-300 hover:text-gray-600 transition-colors"><MoreVertical size={18}/></button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="bg-white border-2 border-dashed rounded-3xl p-24 text-center flex flex-col items-center justify-center grayscale opacity-30">
             <ShieldAlert size={80} className="mb-4 text-gray-300"/>
             <p className="text-xl font-black text-gray-400 uppercase tracking-[0.2em]">Zero Incidents Logged</p>
             <p className="text-sm text-gray-300 mt-2">Semua sistem dalam kondisi aman dan terkendali.</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MasterData, User } from '../../types';
import { Button } from '../Button';
import { 
  Trash2, Plus, Edit2, Save, X, Search, User as UserIcon, 
  Map, Activity, Database, Layout, BedDouble, AlertTriangle, 
  ChevronRight, CheckCircle2 
} from 'lucide-react';

interface DataManagementProps {
  masterData: MasterData;
  onSave: (newData: MasterData) => void;
}

type Tab = 'STAFF' | 'STRUCTURE' | 'MEDICS' | 'REFS';

export const DataManagement: React.FC<DataManagementProps> = ({ masterData, onSave }) => {
  const [activeTab, setActiveTab] = useState<Tab>('STAFF');
  const [selectedUnit, setSelectedUnit] = useState<string>('');
  const [selectedClassGroup, setSelectedClassGroup] = useState<string>('');

  // States for Modals
  const [deleteTarget, setDeleteTarget] = useState<{ 
      type: string, 
      id: string, 
      name: string,
      parentId?: string,
      subCategory?: keyof MasterData['refs'] 
  } | null>(null);

  const [editTarget, setEditTarget] = useState<{
      type: string,
      id: string,
      currentValue: any,
      subCategory?: keyof MasterData['refs']
  } | null>(null);

  const [showNotification, setShowNotification] = useState<string | null>(null);

  const notify = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const handleConfirmedDelete = () => {
    if (!deleteTarget) return;
    const newData = { ...masterData };

    switch (deleteTarget.type) {
      case 'USER':
        newData.users = newData.users.filter(u => u.username !== deleteTarget.id);
        break;
      case 'UNIT':
        newData.units = newData.units.filter(u => u !== deleteTarget.id);
        delete newData.unitToClasses[deleteTarget.id];
        break;
      case 'CLASS':
        if (deleteTarget.parentId) {
          newData.unitToClasses[deleteTarget.parentId] = newData.unitToClasses[deleteTarget.parentId].filter(c => c !== deleteTarget.id);
          delete newData.classToRooms[`${deleteTarget.parentId} - ${deleteTarget.id}`];
        }
        break;
      case 'ROOM':
        if (deleteTarget.parentId) {
          newData.classToRooms[deleteTarget.parentId] = newData.classToRooms[deleteTarget.parentId].filter(r => r !== deleteTarget.id);
          delete newData.roomToBeds[deleteTarget.id];
        }
        break;
      case 'DOCTOR':
        newData.doctors = newData.doctors.filter(d => d !== deleteTarget.id);
        delete newData.doctorMetadata[deleteTarget.id];
        break;
      case 'NURSE':
        newData.nurses = newData.nurses.filter(n => n !== deleteTarget.id);
        break;
      case 'REF':
        if (deleteTarget.subCategory) {
          (newData.refs as any)[deleteTarget.subCategory] = (newData.refs as any)[deleteTarget.subCategory].filter((i: string) => i !== deleteTarget.id);
        }
        break;
    }

    onSave(newData);
    notify(`${deleteTarget.name} berhasil dihapus.`);
    setDeleteTarget(null);
  };

  const handleSaveEdit = (newValue: any) => {
    if (!editTarget) return;
    const newData = { ...masterData };

    switch (editTarget.type) {
      case 'USER_NAME':
        const userIndex = newData.users.findIndex(u => u.username === editTarget.id);
        if (userIndex > -1) newData.users[userIndex].name = newValue;
        break;
      case 'UNIT_NAME':
        const unitIdx = newData.units.indexOf(editTarget.id);
        if (unitIdx > -1) {
          newData.units[unitIdx] = newValue;
          // Migration of keys
          newData.unitToClasses[newValue] = newData.unitToClasses[editTarget.id];
          delete newData.unitToClasses[editTarget.id];
          setSelectedUnit(newValue);
        }
        break;
      case 'DOCTOR_KSM':
        if (newData.doctorMetadata[editTarget.id]) {
          newData.doctorMetadata[editTarget.id].ksm = newValue;
        }
        break;
      case 'REF_ITEM':
        if (editTarget.subCategory) {
           const list = (newData.refs as any)[editTarget.subCategory];
           const idx = list.indexOf(editTarget.id);
           if (idx > -1) list[idx] = newValue;
        }
        break;
    }

    onSave(newData);
    notify("Perubahan berhasil disimpan.");
    setEditTarget(null);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border min-h-[600px] flex flex-col overflow-hidden relative">

      {/* GLOBAL NOTIFICATION */}
      {showNotification && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[200] bg-slate-900 text-white px-6 py-3 rounded-full flex items-center gap-3 shadow-2xl animate-fade-in border border-blue-500/50">
          <CheckCircle2 size={18} className="text-emerald-400"/>
          <span className="text-sm font-bold">{showNotification}</span>
        </div>
      )}

      {/* DELETE CONFIRMATION MODAL */}
      {deleteTarget && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-8 w-full max-w-sm shadow-2xl border border-red-100 animate-fade-in">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-4">
              <AlertTriangle size={32}/>
            </div>
            <h3 className="font-black text-xl mb-2 text-center text-slate-800">Konfirmasi Hapus</h3>
            <p className="text-sm text-gray-500 text-center mb-8 leading-relaxed">
              Apakah Anda yakin ingin menghapus data <b className="text-slate-800">"{deleteTarget.name}"</b>? Tindakan ini tidak dapat dibatalkan.
            </p>
            <div className="flex flex-col gap-2">
              <Button variant="danger" className="w-full py-3 rounded-xl font-bold" onClick={handleConfirmedDelete}>Ya, Hapus Data</Button>
              <Button variant="ghost" className="w-full py-3 font-bold text-gray-400" onClick={() => setDeleteTarget(null)}>Batal</Button>
            </div>
          </div>
        </div>
      )}

      {/* EDIT MODAL */}
      {editTarget && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-8 w-full max-w-md shadow-2xl animate-fade-in">
            <h3 className="font-black text-xl mb-6 text-slate-800 flex items-center gap-2">
              <Edit2 size={20} className="text-blue-500"/> Edit Data
            </h3>
            <div className="space-y-4">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5">Nilai Baru</label>
                <input 
                  autoFocus
                  className="w-full border-2 border-slate-100 rounded-xl p-3 text-sm focus:border-blue-500 outline-none font-bold text-slate-700"
                  defaultValue={editTarget.currentValue}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') handleSaveEdit((e.target as HTMLInputElement).value);
                    if (e.key === 'Escape') setEditTarget(null);
                  }}
                  id="edit-input"
                />
              </div>
            </div>
            <div className="flex justify-end gap-2 mt-8">
              <Button variant="secondary" onClick={() => setEditTarget(null)}>Batal</Button>
              <Button onClick={() => {
                const val = (document.getElementById('edit-input') as HTMLInputElement).value;
                handleSaveEdit(val);
              }}>Simpan Perubahan</Button>
            </div>
          </div>
        </div>
      )}

      {/* TABS NAVBAR */}
      <div className="flex border-b overflow-x-auto bg-slate-50/50">
        {[
          { id: 'STAFF', icon: <UserIcon size={18}/>, label: 'Pengguna & Staf' },
          { id: 'STRUCTURE', icon: <Map size={18}/>, label: 'Hierarki Unit' },
          { id: 'MEDICS', icon: <Activity size={18}/>, label: 'DPJP & Medis' },
          { id: 'REFS', icon: <Database size={18}/>, label: 'Referensi' }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveTab(tab.id as Tab)} 
            className={`px-8 py-5 text-xs font-black uppercase tracking-[0.1em] flex shrink-0 items-center gap-3 transition-all ${activeTab === tab.id ? 'text-blue-600 border-b-4 border-blue-600 bg-white' : 'text-slate-400 hover:bg-white'}`}
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      <div className="p-8 flex-1 overflow-y-auto bg-gray-50/30">
        {/* TAB: STAFF */}
        {activeTab === 'STAFF' && (
          <div className="space-y-6">
            <div className="flex justify-between items-end">
              <div>
                <h3 className="text-2xl font-black text-slate-800">Manajemen Pengguna</h3>
                <p className="text-xs text-gray-400">Kelola kredensial dan hak akses petugas ruangan.</p>
              </div>
              <Button size="sm" className="rounded-full px-6"><Plus size={16} className="mr-2"/> Tambah Akun</Button>
            </div>
            <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
              <table className="w-full text-xs text-left">
                <thead className="bg-slate-100 text-slate-500 font-black uppercase tracking-widest border-b">
                  <tr>
                    <th className="p-5">Nama Lengkap</th>
                    <th className="p-5">Username</th>
                    <th className="p-5">Role</th>
                    <th className="p-5 text-right">Aksi</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {masterData.users.map(u => (
                    <tr key={u.username} className="hover:bg-blue-50/30 transition-colors group">
                      <td className="p-5 font-black text-slate-700">{u.name}</td>
                      <td className="p-5 text-slate-400 font-mono">{u.username}</td>
                      <td className="p-5">
                        <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter border ${u.role === 'SUPER_ADMIN' ? 'bg-purple-50 text-purple-600 border-purple-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                          {u.role}
                        </span>
                      </td>
                      <td className="p-5 text-right">
                        <div className="flex justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => setEditTarget({ type: 'USER_NAME', id: u.username, currentValue: u.name })} className="p-2 text-blue-500 hover:bg-blue-100 rounded-lg"><Edit2 size={14}/></button>
                          <button onClick={() => setDeleteTarget({ type: 'USER', id: u.username, name: u.name })} className="p-2 text-red-400 hover:bg-red-50 rounded-lg"><Trash2 size={14}/></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* TAB: STRUCTURE */}
        {activeTab === 'STRUCTURE' && (
           <div className="space-y-6">
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {/* UNITS */}
                <div className="bg-white border rounded-2xl overflow-hidden flex flex-col h-[550px] shadow-sm">
                  <div className="p-4 bg-slate-900 text-white flex justify-between items-center">
                    <span className="text-[10px] font-black uppercase tracking-widest">1. Unit Pelayanan</span>
                    <button className="hover:bg-white/20 p-1 rounded"><Plus size={14}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-3 space-y-1.5">
                    {masterData.units.map(unit => (
                      <div key={unit} className={`group flex items-center justify-between p-3 rounded-xl transition-all cursor-pointer ${selectedUnit === unit ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-100 text-slate-600'}`}>
                        <div className="flex-1 font-bold text-xs" onClick={() => { setSelectedUnit(unit); setSelectedClassGroup(''); }}>
                          {unit}
                        </div>
                        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity ml-2">
                           <button onClick={() => setEditTarget({ type: 'UNIT_NAME', id: unit, currentValue: unit })} className={`${selectedUnit === unit ? 'text-white/80' : 'text-blue-400'} p-1`}><Edit2 size={12}/></button>
                           <button onClick={() => setDeleteTarget({ type: 'UNIT', id: unit, name: unit })} className={`${selectedUnit === unit ? 'text-white/80' : 'text-red-400'} p-1`}><Trash2 size={12}/></button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* CLASSES */}
                <div className="bg-white border rounded-2xl overflow-hidden flex flex-col h-[550px] shadow-sm">
                  <div className="p-4 bg-slate-800 text-white flex justify-between items-center">
                    <span className="text-[10px] font-black uppercase tracking-widest">2. Kelompok Kelas</span>
                    {selectedUnit && <button className="hover:bg-white/20 p-1 rounded"><Plus size={14}/></button>}
                  </div>
                  <div className="flex-1 overflow-y-auto p-3 space-y-1.5">
                    {selectedUnit ? (masterData.unitToClasses[selectedUnit] || []).map(cls => (
                      <div key={cls} className={`group flex items-center justify-between p-3 rounded-xl transition-all cursor-pointer ${selectedClassGroup === `${selectedUnit} - ${cls}` ? 'bg-blue-500 text-white shadow-md' : 'hover:bg-slate-100 text-slate-600'}`}>
                         <div className="flex-1 font-bold text-xs" onClick={() => setSelectedClassGroup(`${selectedUnit} - ${cls}`)}>
                           {cls}
                         </div>
                         <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity ml-2">
                           <button onClick={() => setDeleteTarget({ type: 'CLASS', id: cls, name: cls, parentId: selectedUnit })} className={`${selectedClassGroup === `${selectedUnit} - ${cls}` ? 'text-white/80' : 'text-red-400'} p-1`}><Trash2 size={12}/></button>
                        </div>
                      </div>
                    )) : <div className="h-full flex items-center justify-center text-[10px] text-slate-300 font-bold uppercase">Pilih Unit</div>}
                  </div>
                </div>

                {/* ROOMS & BEDS */}
                <div className="bg-white border rounded-2xl overflow-hidden flex flex-col h-[550px] shadow-sm">
                  <div className="p-4 bg-slate-700 text-white flex justify-between items-center">
                    <span className="text-[10px] font-black uppercase tracking-widest">3. Ruangan & Bed</span>
                    {selectedClassGroup && <button className="hover:bg-white/20 p-1 rounded"><Plus size={14}/></button>}
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-4">
                    {selectedClassGroup ? (masterData.classToRooms[selectedClassGroup] || []).map(room => (
                      <div key={room} className="border-2 border-slate-50 rounded-2xl overflow-hidden group">
                        <div className="p-3 bg-slate-50 font-black text-[10px] text-slate-600 flex justify-between items-center">
                          <span>{room}</span>
                          <div className="flex gap-2">
                            <button onClick={() => setDeleteTarget({ type: 'ROOM', id: room, name: room, parentId: selectedClassGroup })} className="text-red-300 hover:text-red-500"><Trash2 size={12}/></button>
                          </div>
                        </div>
                        <div className="p-3 grid grid-cols-4 gap-2">
                          {(masterData.roomToBeds[room] || []).map(bed => (
                            <div key={bed} className="text-[9px] bg-white border rounded-lg py-2 text-center font-black text-slate-400 hover:border-blue-200 hover:text-blue-500 transition-all">
                              {bed}
                            </div>
                          ))}
                          <button className="text-[9px] border-2 border-dashed rounded-lg py-2 flex items-center justify-center text-slate-300 hover:text-blue-400 hover:border-blue-200 transition-all"><Plus size={10}/></button>
                        </div>
                      </div>
                    )) : <div className="h-full flex items-center justify-center text-[10px] text-slate-300 font-bold uppercase">Pilih Kelas</div>}
                  </div>
                </div>
             </div>
           </div>
        )}

        {/* TAB: MEDICS */}
        {activeTab === 'MEDICS' && (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* DOCTORS */}
              <div className="bg-white rounded-3xl border shadow-sm flex flex-col h-[500px]">
                <div className="p-5 border-b flex justify-between items-center bg-slate-50/50">
                  <h4 className="font-black text-slate-800 text-sm tracking-tight">Dokter DPJP</h4>
                  <Button size="sm" variant="ghost" className="text-blue-600 font-bold"><Plus size={14} className="mr-1"/> Add</Button>
                </div>
                <div className="flex-1 overflow-y-auto divide-y divide-slate-50">
                  {masterData.doctors.map(doc => (
                    <div key={doc} className="p-4 flex justify-between items-center hover:bg-blue-50/30 group transition-colors">
                      <div>
                        <div className="text-xs font-black text-slate-700">{doc}</div>
                        <div className="text-[9px] text-blue-500 font-bold uppercase tracking-widest">{masterData.doctorMetadata[doc]?.ksm}</div>
                      </div>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => setEditTarget({ type: 'DOCTOR_KSM', id: doc, currentValue: masterData.doctorMetadata[doc]?.ksm })} className="p-2 text-slate-400 hover:text-blue-500"><Edit2 size={14}/></button>
                         <button onClick={() => setDeleteTarget({ type: 'DOCTOR', id: doc, name: doc })} className="p-2 text-slate-400 hover:text-red-500"><Trash2 size={14}/></button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              {/* NURSES */}
