import { AppData, Patient, User, NursingReport, OperationSchedule } from '../types';
import { INITIAL_DATA } from './initialData';

// Kunci database permanen untuk mencegah data hilang saat update kode
const DB_KEY = 'si_baru_db_stable_production_v5';
const API_URL_KEY = 'si_baru_api_url_stable';

/**
 * Logika Smart Merge (Anti-Loss)
 * Menggabungkan data lokal dan cloud tanpa menghapus yang sudah ada.
 */
export const mergeData = (local: AppData, cloud: AppData): AppData => {
    if (!cloud || !cloud.patients) return local;

    const mergedPatients = [...local.patients];
    cloud.patients.forEach(cp => {
        const idx = mergedPatients.findIndex(lp => lp.id === cp.id);
        if (idx === -1) {
            mergedPatients.push(cp);
        } else {
            // Update jika data cloud lebih baru (berdasarkan timestamp jika ada)
            mergedPatients[idx] = cp;
        }
    });

    const mergedReports = [...local.nursingReports];
    cloud.nursingReports.forEach(cr => {
        const idx = mergedReports.findIndex(lr => lr.id === cr.id);
        if (idx === -1) mergedReports.push(cr);
    });

    const mergedOps = [...local.operations];
    cloud.operations.forEach(co => {
        const idx = mergedOps.findIndex(lo => lo.id === co.id);
        if (idx === -1) mergedOps.push(co);
    });

    return {
        ...INITIAL_DATA,
        timestamp: new Date().toISOString(),
        patients: mergedPatients,
        nursingReports: mergedReports,
        operations: mergedOps,
        masterData: { ...INITIAL_DATA.masterData, ...cloud.masterData, users: INITIAL_DATA.masterData.users }
    };
};

export const cleanAndDeduplicate = (data: AppData): AppData => {
    if (!data || !data.patients) return INITIAL_DATA;
    const seenPatients = new Set();
    const cleanPatients = data.patients.filter(p => {
        if (!p || !p.id) return false;
        if (seenPatients.has(p.id)) return false;
        seenPatients.add(p.id);
        return true;
    });
    return { ...data, patients: cleanPatients };
};

export const getDB = (): AppData => {
  const existing = localStorage.getItem(DB_KEY);
  if (existing) {
    try {
      return cleanAndDeduplicate({ ...INITIAL_DATA, ...JSON.parse(existing) });
    } catch (e) { return INITIAL_DATA; }
  }
  return INITIAL_DATA;
};

export const saveDB = (data: AppData): void => {
  data.timestamp = new Date().toISOString();
  localStorage.setItem(DB_KEY, JSON.stringify(cleanAndDeduplicate(data)));
};

export const getApiUrl = (): string => localStorage.getItem(API_URL_KEY) || '';
export const saveApiUrl = (url: string): void => localStorage.setItem(API_URL_KEY, url.trim());

export const syncData = async (forceDownload: boolean = false): Promise<boolean> => {
  const url = getApiUrl();
  if (!url || !url.startsWith('http')) return false;

  try {
    const sep = url.includes('?') ? '&' : '?';
    const response = await fetch(`${url}${sep}t=${Date.now()}`, { cache: 'no-store' });
    const cloudResponse = await response.json();

    if (!cloudResponse || cloudResponse.status !== 'success' || !cloudResponse.data) {
        // Jika cloud kosong atau baru, unggah data lokal kita ke sana
        await uploadData();
        return true;
    }

    const localData = getDB();
    const merged = mergeData(localData, cloudResponse.data);
    saveDB(merged);

    // Sinkronkan balik jika kita punya data yang lebih baru
    await uploadData();
    return true;
  } catch (error) {
    return false;
  }
};

export const uploadData = async (): Promise<boolean> => {
  const url = getApiUrl();
  if (!url || !url.startsWith('http')) return false;
  try {
    const db = getDB();
    const response = await fetch(url, {
      method: 'POST',
      mode: 'cors',
      headers: { 'Content-Type': 'text/plain;charset=utf-8' },
      body: JSON.stringify(db)
    });
    return true;
  } catch (e) { return false; }
};

let uploadTimer: any = null;
export const uploadDataBackground = () => {
    if (uploadTimer) clearTimeout(uploadTimer);
    uploadTimer = setTimeout(() => uploadData(), 2000);
};

export const authenticate = (username: string, password: string): User | null => {
  const db = getDB();
  return db.masterData.users.find(u => u.username === username && u.password === password) || null;
};

export const createPatient = async (patient: Omit<Patient, 'id'>): Promise<Patient> => {
  const db = getDB();
  const newPatient: Patient = { ...patient, id: Date.now().toString() };
  db.patients.push(newPatient);
  saveDB(db);
  uploadDataBackground();
  return newPatient;
};

export const updatePatient = async (id: string, updates: Partial<Patient>): Promise<Patient | null> => {
  const db = getDB();
  const idx = db.patients.findIndex(p => String(p.id) === String(id));
  if (idx === -1) return null;
  db.patients[idx] = { ...db.patients[idx], ...updates };
  saveDB(db);
  uploadDataBackground();
  return db.patients[idx];
};

