import React, { useState } from 'react';
import { MasterData, User, UserRole } from '../../types';
import { Button } from '../Button';
import { 
  Trash2, Plus, Edit2, Save, X, Search, User as UserIcon, 
  Map, Activity, Database, Layout, BedDouble, AlertTriangle, 
  ChevronRight, CheckCircle2, Eye, EyeOff, Shield
} from 'lucide-react';

interface DataManagementProps {
  masterData: MasterData;
  onSave: (newData: MasterData) => void;
}

type Tab = 'STAFF' | 'STRUCTURE' | 'MEDICS' | 'REFS';

export const DataManagement: React.FC<DataManagementProps> = ({ masterData, onSave }) => {
  const [activeTab, setActiveTab] = useState<Tab>('STAFF');
  const [selectedUnit, setSelectedUnit] = useState<string>('');
  const [selectedClassGroup, setSelectedClassGroup] = useState<string>('');

  // Modal States
  const [isAddUserOpen, setIsAddUserOpen] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [newUser, setNewUser] = useState<Partial<User>>({
    role: 'STAFF',
    position: 'Perawat Assosiate'
  });

  const [deleteTarget, setDeleteTarget] = useState<{ 
      type: string, 
      id: string, 
      name: string,
      parentId?: string,
      subCategory?: keyof MasterData['refs'] 
  } | null>(null);

  const [editTarget, setEditTarget] = useState<{
      type: string,
      id: string,
      currentValue: any,
      subCategory?: keyof MasterData['refs']
  } | null>(null);

  const [showNotification, setShowNotification] = useState<string | null>(null);

  const notify = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const handleAddAccount = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newUser.username || !newUser.name || !newUser.password) {
      notify("Harap isi semua field wajib.");
      return;
    }

    if (masterData.users.find(u => u.username === newUser.username)) {
      notify("Username sudah digunakan.");
      return;
    }

    const updatedData = { ...masterData };
    updatedData.users = [...updatedData.users, newUser as User];
    onSave(updatedData);

    setIsAddUserOpen(false);
    setNewUser({ role: 'STAFF', position: 'Perawat Assosiate' });
    notify(`Akun "${newUser.name}" berhasil ditambahkan.`);
  };

  const handleConfirmedDelete = () => {
    if (!deleteTarget) return;
    const newData = { ...masterData };

    switch (deleteTarget.type) {
      case 'USER':
        newData.users = newData.users.filter(u => u.username !== deleteTarget.id);
        break;
      case 'UNIT':
        newData.units = newData.units.filter(u => u !== deleteTarget.id);
        delete newData.unitToClasses[deleteTarget.id];
        break;
      case 'CLASS':
        if (deleteTarget.parentId) {
          newData.unitToClasses[deleteTarget.parentId] = newData.unitToClasses[deleteTarget.parentId].filter(c => c !== deleteTarget.id);
          delete newData.classToRooms[`${deleteTarget.parentId} - ${deleteTarget.id}`];
        }
        break;
      case 'ROOM':
        if (deleteTarget.parentId) {
          newData.classToRooms[deleteTarget.parentId] = newData.classToRooms[deleteTarget.parentId].filter(r => r !== deleteTarget.id);
          delete newData.roomToBeds[deleteTarget.id];
        }
        break;
      case 'DOCTOR':
        newData.doctors = newData.doctors.filter(d => d !== deleteTarget.id);
        delete newData.doctorMetadata[deleteTarget.id];
        break;
      case 'NURSE':
        newData.nurses = newData.nurses.filter(n => n !== deleteTarget.id);
        break;
      case 'REF':
        if (deleteTarget.subCategory) {
          (newData.refs as any)[deleteTarget.subCategory] = (newData.refs as any)[deleteTarget.subCategory].filter((i: string) => i !== deleteTarget.id);
        }
        break;
    }

    onSave(newData);
    notify(`${deleteTarget.name} berhasil dihapus.`);
    setDeleteTarget(null);
  };

  const handleSaveEdit = (newValue: any) => {
    if (!editTarget) return;
    const newData = { ...masterData };

    switch (editTarget.type) {
      case 'USER_NAME':
        const userIndex = newData.users.findIndex(u => u.username === editTarget.id);
        if (userIndex > -1) newData.users[userIndex].name = newValue;
        break;
      case 'UNIT_NAME':
        const unitIdx = newData.units.indexOf(editTarget.id);
        if (unitIdx > -1) {
          newData.units[unitIdx] = newValue;
          newData.unitToClasses[newValue] = newData.unitToClasses[editTarget.id];
          delete newData.unitToClasses[editTarget.id];
          setSelectedUnit(newValue);
        }
        break;
      case 'DOCTOR_KSM':
        if (newData.doctorMetadata[editTarget.id]) {
          newData.doctorMetadata[editTarget.id].ksm = newValue;
        }
        break;
      case 'REF_ITEM':
        if (editTarget.subCategory) {
           const list = (newData.refs as any)[editTarget.subCategory];
           const idx = list.indexOf(editTarget.id);
           if (idx > -1) list[idx] = newValue;
        }
        break;
    }

    onSave(newData);
    notify("Perubahan berhasil disimpan.");
    setEditTarget(null);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border min-h-[600px] flex flex-col overflow-hidden relative">

      {showNotification && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[200] bg-slate-900 text-white px-6 py-3 rounded-full flex items-center gap-3 shadow-2xl animate-fade-in border border-blue-500/50">
          <CheckCircle2 size={18} className="text-emerald-400"/>
          <span className="text-sm font-bold">{showNotification}</span>
        </div>
      )}

      {/* TAMBAH AKUN MODAL */}
      {isAddUserOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-8 w-full max-w-lg shadow-2xl animate-fade-in">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-black text-xl text-slate-800 flex items-center gap-2">
                <Plus size={24} className="text-blue-600"/> Tambah Akun Baru
              </h3>
              <button onClick={() => setIsAddUserOpen(false)} className="text-slate-400 hover:text-slate-600 p-2">
                <X size={20}/>
              </button>
            </div>

            <form onSubmit={handleAddAccount} className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="col-span-2">
                <label className="block text-[10px] font-black text-gray-500 uppercase mb-1 tracking-widest">Nama Lengkap</label>
                <input required className="w-full border-2 border-slate-100 rounded-xl p-3 text-sm outline-none focus:border-blue-500 font-bold" value={newUser.name || ''} onChange={e => setNewUser({...newUser, name: e.target.value})}/>
              </div>

              <div>
                <label className="block text-[10px] font-black text-gray-500 uppercase mb-1 tracking-widest">Username</label>
                <input required className="w-full border-2 border-slate-100 rounded-xl p-3 text-sm outline-none focus:border-blue-500 font-bold" value={newUser.username || ''} onChange={e => setNewUser({...newUser, username: e.target.value.toLowerCase().replace(/\s/g, '')})}/>
              </div>

              <div>
                <label className="block text-[10px] font-black text-gray-500 uppercase mb-1 tracking-widest">Password</label>
                <div className="relative">
                  <input required type={showPassword ? 'text' : 'password'} className="w-full border-2 border-slate-100 rounded-xl p-3 text-sm outline-none focus:border-blue-500 font-bold" value={newUser.password || ''} onChange={e => setNewUser({...newUser, password: e.target.value})}/>
                  <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-blue-500">
                    {showPassword ? <EyeOff size={16}/> : <Eye size={16}/>}
                  </button>
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-gray-500 uppercase mb-1 tracking-widest">Hak Akses (Role)</label>
                <select className="w-full border-2 border-slate-100 rounded-xl p-3 text-sm outline-none focus:border-blue-500 font-bold bg-white" value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value as UserRole})}>
                  <option value="STAFF">STAFF (Perawat Pelaksana)</option>
                  <option value="PPJA">PPJA (Perawat Primer)</option>
                  <option value="PIC">PIC (Admin & Mutu)</option>
                  <option value="ADMIN_RUANGAN">ADMIN RUANGAN (Sekertaris/Karper)</option>
                  <option value="SUPER_ADMIN">SUPER ADMIN</option>
                </select>
              </div>

              <div>
                <label className="block text-[10px] font-black text-gray-500 uppercase mb-1 tracking-widest">Posisi / Jabatan</label>
                <select className="w-full border-2 border-slate-100 rounded-xl p-3 text-sm outline-none focus:border-blue-500 font-bold bg-white" value={newUser.position} onChange={e => setNewUser({...newUser, position: e.target.value})}>
                  {masterData.refs.positions.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>

              <div className="col-span-2 flex justify-end gap-3 mt-6 pt-6 border-t">
                <Button type="button" variant="ghost" className="px-8 font-bold" onClick={() => setIsAddUserOpen(false)}>Batal</Button>
                <Button type="submit" className="px-10 rounded-xl shadow-lg shadow-blue-200">Simpan Akun</Button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* DELETE CONFIRMATION MODAL */}
      {deleteTarget && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-8 w-full max-w-sm shadow-2xl border border-red-100 animate-fade-in">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-4">
              <AlertTriangle size={32}/>
            </div>
            <h3 className="font-black text-xl mb-2 text-center text-slate-800">Konfirmasi Hapus</h3>
            <p className="text-sm text-gray-500 text-center mb-8 leading-relaxed">
              Apakah Anda yakin ingin menghapus data <b className="text-slate-800">"{deleteTarget.name}"</b>? Tindakan ini tidak dapat dibatalkan.
