                <input 
                  autoFocus
                  className="w-full border-2 border-slate-100 rounded-xl p-3 text-sm focus:border-blue-500 outline-none font-bold text-slate-700"
                  defaultValue={editTarget.currentValue}
                  id="edit-input"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') handleSaveEdit((e.target as HTMLInputElement).value);
                    if (e.key === 'Escape') setEditTarget(null);
                  }}
                />
              </div>
            </div>
            <div className="flex justify-end gap-2 mt-8">
              <Button variant="secondary" onClick={() => setEditTarget(null)}>Batal</Button>
              <Button onClick={() => {
                const val = (document.getElementById('edit-input') as HTMLInputElement).value;
                handleSaveEdit(val);
              }}>Simpan Perubahan</Button>
            </div>
          </div>
        </div>
      )}

      {/* TABS NAVBAR */}
      <div className="flex border-b overflow-x-auto bg-slate-50/50">
        {[
          { id: 'STAFF', icon: <UserIcon size={18}/>, label: 'Pengguna & Staf' },
          { id: 'STRUCTURE', icon: <Map size={18}/>, label: 'Hierarki Unit' },
          { id: 'MEDICS', icon: <Activity size={18}/>, label: 'DPJP & Medis' },
          { id: 'REFS', icon: <Database size={18}/>, label: 'Referensi' }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveTab(tab.id as Tab)} 
            className={`px-8 py-5 text-xs font-black uppercase tracking-[0.1em] flex shrink-0 items-center gap-3 transition-all ${activeTab === tab.id ? 'text-blue-600 border-b-4 border-blue-600 bg-white' : 'text-slate-400 hover:bg-white'}`}
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      <div className="p-8 flex-1 overflow-y-auto bg-gray-50/30">
        {/* TAB: STAFF */}
        {activeTab === 'STAFF' && (
          <div className="space-y-6">
            <div className="flex justify-between items-end">
              <div>
                <h3 className="text-2xl font-black text-slate-800">Manajemen Pengguna</h3>
                <p className="text-xs text-gray-400">Kelola kredensial dan hak akses petugas ruangan.</p>
              </div>
              <Button onClick={() => setIsAddUserOpen(true)} size="sm" className="rounded-full px-6 shadow-md"><Plus size={16} className="mr-2"/> Tambah Akun</Button>
            </div>
            <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
              <table className="w-full text-xs text-left">
                <thead className="bg-slate-100 text-slate-500 font-black uppercase tracking-widest border-b">
                  <tr>
                    <th className="p-5">Nama Lengkap</th>
                    <th className="p-5">Username</th>
                    <th className="p-5">Role</th>
                    <th className="p-5">Posisi</th>
                    <th className="p-5 text-right">Aksi</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {masterData.users.map(u => (
                    <tr key={u.username} className="hover:bg-blue-50/30 transition-colors group">
                      <td className="p-5 font-black text-slate-700">{u.name}</td>
                      <td className="p-5 text-slate-400 font-mono font-bold tracking-tight">{u.username}</td>
                      <td className="p-5">
                        <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter border ${u.role === 'SUPER_ADMIN' ? 'bg-purple-50 text-purple-600 border-purple-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                          {u.role.replace('_', ' ')}
                        </span>
                      </td>
                      <td className="p-5 text-slate-500 font-medium italic">{u.position}</td>
                      <td className="p-5 text-right">
                        <div className="flex justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => setEditTarget({ type: 'USER_NAME', id: u.username, currentValue: u.name })} className="p-2 text-blue-500 hover:bg-blue-100 rounded-lg"><Edit2 size={14}/></button>
                          <button onClick={() => setDeleteTarget({ type: 'USER', id: u.username, name: u.name })} className="p-2 text-red-400 hover:bg-red-50 rounded-lg"><Trash2 size={14}/></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* TAB: STRUCTURE */}
        {activeTab === 'STRUCTURE' && (
           <div className="space-y-6">
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white border rounded-2xl overflow-hidden flex flex-col h-[550px] shadow-sm">
                  <div className="p-4 bg-slate-900 text-white flex justify-between items-center">
                    <span className="text-[10px] font-black uppercase tracking-widest">1. Unit Pelayanan</span>
                    <button className="hover:bg-white/20 p-1 rounded"><Plus size={14}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-3 space-y-1.5">
                    {masterData.units.map(unit => (
                      <div key={unit} className={`group flex items-center justify-between p-3 rounded-xl transition-all cursor-pointer ${selectedUnit === unit ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-100 text-slate-600'}`}>
                        <div className="flex-1 font-bold text-xs" onClick={() => { setSelectedUnit(unit); setSelectedClassGroup(''); }}>
                          {unit}
                        </div>
                        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity ml-2">
                           <button onClick={() => setEditTarget({ type: 'UNIT_NAME', id: unit, currentValue: unit })} className={`${selectedUnit === unit ? 'text-white/80' : 'text-blue-400'} p-1`}><Edit2 size={12}/></button>
                           <button onClick={() => setDeleteTarget({ type: 'UNIT', id: unit, name: unit })} className={`${selectedUnit === unit ? 'text-white/80' : 'text-red-400'} p-1`}><Trash2 size={12}/></button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="bg-white border rounded-2xl overflow-hidden flex flex-col h-[550px] shadow-sm">
                  <div className="p-4 bg-slate-800 text-white flex justify-between items-center">
                    <span className="text-[10px] font-black uppercase tracking-widest">2. Kelompok Kelas</span>
                    {selectedUnit && <button className="hover:bg-white/20 p-1 rounded"><Plus size={14}/></button>}
                  </div>
                  <div className="flex-1 overflow-y-auto p-3 space-y-1.5">
                    {selectedUnit ? (masterData.unitToClasses[selectedUnit] || []).map(cls => (
                      <div key={cls} className={`group flex items-center justify-between p-3 rounded-xl transition-all cursor-pointer ${selectedClassGroup === `${selectedUnit} - ${cls}` ? 'bg-blue-500 text-white shadow-md' : 'hover:bg-slate-100 text-slate-600'}`}>
                         <div className="flex-1 font-bold text-xs" onClick={() => setSelectedClassGroup(`${selectedUnit} - ${cls}`)}>
                           {cls}
                         </div>
                         <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity ml-2">
                           <button onClick={() => setDeleteTarget({ type: 'CLASS', id: cls, name: cls, parentId: selectedUnit })} className={`${selectedClassGroup === `${selectedUnit} - ${cls}` ? 'text-white/80' : 'text-red-400'} p-1`}><Trash2 size={12}/></button>
                        </div>
                      </div>
                    )) : <div className="h-full flex items-center justify-center text-[10px] text-slate-300 font-bold uppercase">Pilih Unit</div>}
                  </div>
                </div>

                <div className="bg-white border rounded-2xl overflow-hidden flex flex-col h-[550px] shadow-sm">
                  <div className="p-4 bg-slate-700 text-white flex justify-between items-center">
                    <span className="text-[10px] font-black uppercase tracking-widest">3. Ruangan & Bed</span>
                    {selectedClassGroup && <button className="hover:bg-white/20 p-1 rounded"><Plus size={14}/></button>}
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-4">
                    {selectedClassGroup ? (masterData.classToRooms[selectedClassGroup] || []).map(room => (
                      <div key={room} className="border-2 border-slate-50 rounded-2xl overflow-hidden group">
                        <div className="p-3 bg-slate-50 font-black text-[10px] text-slate-600 flex justify-between items-center">
                          <span>{room}</span>
                          <div className="flex gap-2">
                            <button onClick={() => setDeleteTarget({ type: 'ROOM', id: room, name: room, parentId: selectedClassGroup })} className="text-red-300 hover:text-red-500"><Trash2 size={12}/></button>
                          </div>
                        </div>
                        <div className="p-3 grid grid-cols-4 gap-2">
                          {(masterData.roomToBeds[room] || []).map(bed => (
                            <div key={bed} className="text-[9px] bg-white border rounded-lg py-2 text-center font-black text-slate-400 hover:border-blue-200 hover:text-blue-500 transition-all">
                              {bed}
                            </div>
                          ))}
                          <button className="text-[9px] border-2 border-dashed rounded-lg py-2 flex items-center justify-center text-slate-300 hover:text-blue-400 hover:border-blue-200 transition-all"><Plus size={10}/></button>
                        </div>
                      </div>
                    )) : <div className="h-full flex items-center justify-center text-[10px] text-slate-300 font-bold uppercase">Pilih Kelas</div>}
                  </div>
                </div>
             </div>
           </div>
        )}

        {/* TAB: MEDICS */}
        {activeTab === 'MEDICS' && (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="bg-white rounded-3xl border shadow-sm flex flex-col h-[500px]">
                <div className="p-5 border-b flex justify-between items-center bg-slate-50/50">
                  <h4 className="font-black text-slate-800 text-sm tracking-tight">Dokter DPJP</h4>
                  <Button size="sm" variant="ghost" className="text-blue-600 font-bold"><Plus size={14} className="mr-1"/> Add</Button>
                </div>
                <div className="flex-1 overflow-y-auto divide-y divide-slate-50">
                  {masterData.doctors.map(doc => (
                    <div key={doc} className="p-4 flex justify-between items-center hover:bg-blue-50/30 group transition-colors">
                      <div>
                        <div className="text-xs font-black text-slate-700">{doc}</div>
                        <div className="text-[9px] text-blue-500 font-bold uppercase tracking-widest">{masterData.doctorMetadata[doc]?.ksm}</div>
                      </div>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => setEditTarget({ type: 'DOCTOR_KSM', id: doc, currentValue: masterData.doctorMetadata[doc]?.ksm })} className="p-2 text-slate-400 hover:text-blue-500"><Edit2 size={14}/></button>
                         <button onClick={() => setDeleteTarget({ type: 'DOCTOR', id: doc, name: doc })} className="p-2 text-slate-400 hover:text-red-500"><Trash2 size={14}/></button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="bg-white rounded-3xl border shadow-sm flex flex-col h-[500px]">
                <div className="p-5 border-b flex justify-between items-center bg-slate-50/50">
                  <h4 className="font-black text-slate-800 text-sm tracking-tight">Perawat Ruangan</h4>
                  <Button size="sm" variant="ghost" className="text-blue-600 font-bold"><Plus size={14} className="mr-1"/> Add</Button>
                </div>
                <div className="flex-1 overflow-y-auto divide-y divide-slate-50">
                  {masterData.nurses.map(nurse => (
                    <div key={nurse} className="p-4 flex justify-between items-center hover:bg-blue-50/30 group transition-colors">
                      <div className="text-xs font-bold text-slate-600">{nurse}</div>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => setDeleteTarget({ type: 'NURSE', id: nurse, name: nurse })} className="p-2 text-slate-400 hover:text-red-500"><Trash2 size={14}/></button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* TAB: REFS */}
        {activeTab === 'REFS' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
             {Object.entries(masterData.refs).map(([key, list]) => (
                <div key={key} className="bg-white p-6 border rounded-3xl shadow-sm flex flex-col h-[320px] hover:shadow-md transition-shadow group/card">
                   <h4 className="font-black text-[10px] text-blue-900 uppercase tracking-[0.2em] mb-4 pb-3 border-b flex justify-between items-center">
                      {key.replace(/([A-Z])/g, ' $1')}
                      <button className="text-blue-400 hover:scale-125 transition-transform"><Plus size={14}/></button>
                   </h4>
                   <div className="flex-1 overflow-y-auto space-y-1 pr-2">
                      {(list as string[]).map(item => (
                         <div key={item} className="flex justify-between items-center py-2 px-3 rounded-xl hover:bg-slate-50 group transition-colors">
                            <span className="text-[11px] font-bold text-slate-600">{item}</span>
                            <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                               <button onClick={() => setEditTarget({ type: 'REF_ITEM', id: item, currentValue: item, subCategory: key as any })} className="text-slate-300 hover:text-blue-500"><Edit2 size={11}/></button>
                               <button onClick={() => setDeleteTarget({ type: 'REF', id: item, name: item, subCategory: key as any })} className="text-slate-300 hover:text-red-500"><Trash2 size={11}/></button>
                            </div>
                         </div>
                      ))}
                   </div>
                </div>
             ))}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { DataManagement } from './components/Administrator/DataManagement';
import { FinanceModule } from './components/Administration/FinanceModule';
import { IncidentModule } from './components/Incidents/IncidentModule';
import { Button } from './components/Button';
import { getDB, saveDB, uploadDataBackground } from './db';
import { AppData, User, FinanceRecord, IncidentReport } from './types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  Cell
} from 'recharts';
import { Activity, Wallet, AlertCircle, Calendar, Plus, Search, Filter, TrendingUp, Users, ShieldAlert, BarChart3, Clock } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>({ 
    username: 'administrator', 
    name: 'Super User', 
    role: 'SUPER_ADMIN', 
    position: 'Super User' 
  });
  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [appData, setAppData] = useState<AppData>(getDB());

  // Background sync simulation or periodic refresh can be added here
  useEffect(() => {
    // Initial load already handled by useState(getDB())
  }, []);

  const handleUpdateAppData = (newData: AppData) => {
    setAppData(newData);
    saveDB(newData);
    uploadDataBackground();
  };

  const handleAddFinance = (rec: FinanceRecord) => {
    const newData = { ...appData };
    newData.financeRecords = [...(newData.financeRecords || []), rec];
    handleUpdateAppData(newData);
  };

  const handleAddIncident = (rep: IncidentReport) => {
    const newData = { ...appData };
    newData.incidentReports = [...(newData.incidentReports || []), rep];
    handleUpdateAppData(newData);
  };

  const handleUpdateIncident = (id: string, status: IncidentReport['status']) => {
    const newData = { ...appData };
    newData.incidentReports = (newData.incidentReports || []).map(r => r.id === id ? { ...r, status } : r);
    handleUpdateAppData(newData);
  };

  const handleUpdateMasterData = (newMasterData: AppData['masterData']) => {
    const newData = { ...appData, masterData: newMasterData };
    handleUpdateAppData(newData);
  };

  const handleLogout = () => setUser(null);

  const renderContent = () => {
    const financeRecords = appData.financeRecords || [];
    const incidentReports = appData.incidentReports || [];
    const openIncidents = incidentReports.filter(i => i.status !== 'RESOLVED');

    switch (activeMenu) {
      case 'dashboard':
        return (
          <div className="space-y-6 animate-fade-in">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              <div className="bg-white p-6 rounded-2xl border shadow-sm flex flex-col items-center justify-center text-center group hover:scale-105 transition-transform">
                <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl mb-3 group-hover:bg-blue-600 group-hover:text-white transition-colors"><Activity size={24}/></div>
                <div className="text-3xl font-black text-slate-800">12</div>
                <div className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-1">Operasi Harian</div>
              </div>
              <div className="bg-white p-6 rounded-2xl border shadow-sm flex flex-col items-center justify-center text-center group hover:scale-105 transition-transform">
                <div className="p-3 bg-emerald-50 text-emerald-600 rounded-2xl mb-3 group-hover:bg-emerald-600 group-hover:text-white transition-colors"><Wallet size={24}/></div>
                <div className="text-3xl font-black text-emerald-600">
                   {(financeRecords.filter(f => f.type === 'INCOME').reduce((a, b) => a + b.amount, 0) / 1000000).toFixed(1)}M
                </div>
                <div className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-1">Revenue Pelayanan</div>
              </div>
              <div className="bg-white p-6 rounded-2xl border shadow-sm flex flex-col items-center justify-center text-center group hover:scale-105 transition-transform">
                <div className="p-3 bg-red-50 text-red-600 rounded-2xl mb-3 group-hover:bg-red-600 group-hover:text-white transition-colors"><AlertCircle size={24}/></div>
                <div className="text-3xl font-black text-red-600">{openIncidents.length}</div>
                <div className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-1">Insiden Aktif</div>
              </div>
              <div className="bg-white p-6 rounded-2xl border shadow-sm flex flex-col items-center justify-center text-center group hover:scale-105 transition-transform">
                <div className="p-3 bg-indigo-50 text-indigo-600 rounded-2xl mb-3 group-hover:bg-indigo-600 group-hover:text-white transition-colors"><Users size={24}/></div>
                <div className="text-3xl font-black text-indigo-600">{appData.masterData.doctors.length}</div>
                <div className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-1">Tenaga Ahli</div>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-2 bg-white p-8 rounded-3xl border shadow-sm h-[450px] flex flex-col relative overflow-hidden">
                <div className="flex justify-between items-center mb-10">
                  <div>
                    <h4 className="font-black text-slate-800 text-xl tracking-tight flex items-center gap-2">
                       <BarChart3 className="text-blue-600"/> Analisis Performance Unit
                    </h4>
                    <p className="text-xs text-gray-400">Distribusi finansial berdasarkan kategori transaksi.</p>
                  </div>
                  <div className="bg-blue-50 text-blue-600 px-4 py-2 rounded-full text-[10px] font-black tracking-widest uppercase">REAL-TIME SYNC</div>
                </div>

                <div className="flex-1">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={[
                      { name: 'Income', val: financeRecords.filter(f => f.type === 'INCOME').reduce((a,b) => a+b.amount, 0) },
                      { name: 'Expense', val: financeRecords.filter(f => f.type === 'EXPENSE').reduce((a,b) => a+b.amount, 0) },
                      { name: 'Target', val: 500000000 }
                    ]}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} opacity={0.3} />
                      <XAxis dataKey="name" fontSize={12} fontStyle="bold" tickLine={false} axisLine={false} />
                      <YAxis fontSize={10} tickLine={false} axisLine={false} tickFormatter={(v) => `Rp${v/1000000}M`} />
                      <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                      <Bar dataKey="val" radius={[8, 8, 0, 0]}>
                        <Cell fill="#10b981" />
                        <Cell fill="#ef4444" />
                        <Cell fill="#cbd5e1" />
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </div>

              <div className="bg-white p-8 rounded-3xl border shadow-sm flex flex-col h-[450px]">
                <div className="flex justify-between items-center mb-8">
                  <h4 className="font-black text-slate-800 text-xl tracking-tight flex items-center gap-2">
                    <ShieldAlert className="text-red-500" size={24}/> PIC Alerts
                  </h4>
                  <span className="animate-pulse bg-red-500 w-2 h-2 rounded-full"></span>
                </div>
                <div className="flex-1 overflow-y-auto pr-2 space-y-4">
                  {incidentReports.length > 0 ? incidentReports.slice(-5).reverse().map(i => (
                    <div key={i.id} className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex flex-col gap-2 hover:bg-red-50/50 transition-colors border-l-4 border-l-red-500">
                      <div className="flex justify-between items-center">
                        <span className="text-[10px] font-black text-slate-400 tracking-widest uppercase">{i.location}</span>
                        <span className={`text-[9px] font-black px-2 py-0.5 rounded border ${i.status === 'NEW' ? 'bg-red-100 text-red-700' : 'bg-blue-100 text-blue-700'}`}>{i.status}</span>
                      </div>
                      <div className="text-xs font-black text-slate-800 line-clamp-1">{i.incidentType}</div>
                      <div className="text-[10px] text-gray-500 flex items-center gap-2">
                         <Clock size={10}/> {i.date}
                      </div>
                    </div>
                  )) : (
                    <div className="h-full flex flex-col items-center justify-center grayscale opacity-20 py-10">
                      <ShieldAlert size={64} className="mb-4"/>
                      <p className="text-[10px] font-black uppercase tracking-widest">No Alerts</p>
                    </div>
                  )}
                </div>
                <button 
                  onClick={() => setActiveMenu('inc-report')}
                  className="mt-6 w-full py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-slate-800 transition-colors shadow-lg shadow-slate-200"
                >
                  Buka Modul Insiden
                </button>
              </div>
            </div>
          </div>
        );

      case 'admin-data':
        return <DataManagement masterData={appData.masterData} onSave={handleUpdateMasterData} />;

      case 'adm-finance':
        return <FinanceModule records={financeRecords} masterData={appData.masterData} onAddRecord={handleAddFinance} />;

      case 'inc-report':
        return <IncidentModule reports={incidentReports} onAddReport={handleAddIncident} onUpdateStatus={handleUpdateIncident} />;

      default:
        return (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 p-24 bg-white rounded-3xl border-2 border-dashed">
            <div className="p-6 bg-slate-50 rounded-full mb-6">
               <Activity size={80} className="opacity-10"/>
            </div>
            <p className="text-2xl font-black text-slate-800 uppercase tracking-widest">Under Construction</p>
            <p className="text-sm text-gray-400 mt-2 text-center max-w-sm">Modul "{activeMenu}" sedang disiapkan untuk rilis berikutnya.</p>
          </div>
        );
    }
  };

  return (
    <Layout 
      user={user} 
      onLogout={handleLogout} 
      onNavigate={setActiveMenu} 
      activeMenu={activeMenu}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;
